/// Default keychain service-name prefix for the session token (one per
/// tenant). The matching account-name is `session_token`. The Tauri
/// shell reads this entry at startup to know the bearer token to
/// present.
const SESSION_TOKEN_ACCOUNT: &str = "session_token";

fn keychain_service_for(tenant: &str) -> String {
    format!("aberp.nav.{tenant}")
}

/// Persisted artifacts (cert PEM + key PEM + fingerprint) for the
/// loopback HTTPS listener live in `~/.aberp/serve/<tenant>/`. ADR-0007
/// §Transport names "next to the keychain material" — for the
/// per-platform Keychain/Credential-Manager/secret-service backends
/// "next to" is the user-home convention. A future ADR can pick a
/// per-OS path if needed; for now the user-home posture works on all
/// three platforms.
fn serve_artifacts_dir(tenant: &str) -> Result<PathBuf> {
    let home = dirs_home_or_loud_fail()?;
    Ok(home.join(".aberp").join("serve").join(tenant))
}

/// We deliberately do NOT import the `dirs` crate (one more dep, one
/// more supply-chain surface). `std::env::var("HOME")` covers macOS
/// and Linux; `USERPROFILE` covers Windows. Loud-fail if neither is
/// set per CLAUDE.md rule 12.
fn dirs_home_or_loud_fail() -> Result<PathBuf> {
    if let Ok(h) = std::env::var("HOME") {
        if !h.is_empty() {
            return Ok(PathBuf::from(h));
        }
    }
    if let Ok(h) = std::env::var("USERPROFILE") {
        if !h.is_empty() {
            return Ok(PathBuf::from(h));
        }
    }
    Err(anyhow!(
        "neither HOME nor USERPROFILE is set — cannot locate ~/.aberp/serve/<tenant>/"
    ))
}

/// S165 / deliverable #5 — the hülye-biztos cross-stream guard. A
/// PRODUCTION build (compiled `--features production`) MUST run as
/// `tenant=prod`; a DEV build MUST NOT run as `tenant=prod`. Either
/// mismatch is a loud `exit(1)` with a remediation hint — never a
/// silent wrong-environment start (CLAUDE.md rule 12). The prod/test
/// choice is baked in at compile time, so the two streams can never
/// cross: a dev binary cannot touch real NAV even if launched as prod.
fn guard_tenant_matches_build(tenant: &str) {
    if crate::build_profile::IS_PRODUCTION_BUILD && tenant != "prod" {
        eprintln!(
            "❌ FATAL: this is a PRODUCTION build but ABERP_TENANT={tenant} (expected 'prod'). \
             Refusing to start."
        );
        eprintln!("   Either: launch with `run/run_prod.sh` (sets ABERP_TENANT=prod), OR");
        eprintln!("   re-build without --features production for dev use.");
        std::process::exit(1);
    }
    if !crate::build_profile::IS_PRODUCTION_BUILD && tenant == "prod" {
        eprintln!("❌ FATAL: this is a DEV build but ABERP_TENANT=prod. Refusing to start.");
        eprintln!("   Either: launch with `run/run_prod.sh` (compiles --features production), OR");
        eprintln!("   set ABERP_TENANT=test (or another non-prod tenant).");
        std::process::exit(1);
    }
}

/// S165 / deliverable #3 — one-shot boot banner. PRODUCTION builds get a
/// loud red/yellow REAL-NAV warning; dev builds get a dim one-liner.
/// Bilingual (HU + EN) per the closed-vocab banner constraint. ANSI
/// colours are emitted only when stderr is a real terminal so the Tauri
/// stderr-pump's log ring does not show escape-code garbage.
fn print_boot_banner(tenant: &str) {
    use std::io::IsTerminal as _;
    let color = std::io::stderr().is_terminal();
    let endpoint = crate::build_profile::nav_endpoint().hostname();

    // ANSI helpers — no-ops when the sink is not a terminal.
    let red_bold = if color { "\x1b[1;31m" } else { "" };
    let yellow = if color { "\x1b[33m" } else { "" };
    let dim = if color { "\x1b[2m" } else { "" };
    let reset = if color { "\x1b[0m" } else { "" };

    if crate::build_profile::IS_PRODUCTION_BUILD {
        let rule = "═══════════════════════════════════════════════════════";
        eprintln!("{red_bold}{rule}{reset}");
        eprintln!("{red_bold}  ⚠️  PRODUCTION MODE — REAL NAV — REAL EMAILS{reset}");
        eprintln!("{yellow}      ÉLES ÜZEM — VALÓDI NAV — VALÓDI E-MAILEK{reset}");
        eprintln!("{red_bold}  tenant={tenant}  endpoint={endpoint}{reset}");
        eprintln!("{red_bold}{rule}{reset}");
    } else {
        eprintln!("{dim}[dev] ABERP — tenant={tenant}  endpoint={endpoint}{reset}");
        eprintln!("{dim}      [teszt] nincs valódi fiskális hatás / no real fiscal effect{reset}");
    }
}

/// S166 / prod-prep PR #2 — outcome of [`sanity_check_environment`].
///
/// `fatal` is `Some(bilingual message)` when a check failed in a way that
/// must refuse the boot; the caller prints it to stderr and `exit(1)`.
/// `warnings` are non-fatal advisories the caller logs via `tracing::warn!`.
pub(crate) struct SanityReport {
    pub fatal: Option<String>,
    pub warnings: Vec<String>,
}

/// S166 / prod-prep PR #2 — the SECOND refuse-to-start guard pass, after
/// [`guard_tenant_matches_build`]. That guard cross-checks the build vs
/// the tenant NAME; this one cross-checks the build vs the on-disk +
/// keychain ENVIRONMENT.
///
/// PRODUCTION builds enforce:
///   A. seller.toml identity — a PRESENT seller.toml whose `tax_number`
///      differs from the documented prod entity is FATAL. (A *missing*
///      seller.toml is NOT fatal here: the existing `NeedsSellerConfig`
///      boot state drives the seller-config wizard.)
///   B. NAV credentials — missing creds are FATAL only if the first-launch
///      ceremony was already completed (touchfile present) — that means
///      the keychain entries were deleted out from under a configured
///      install. Missing creds + no touchfile is the legitimate
///      first-launch path: not fatal, the wizard will populate them.
///   C. SMTP — a missing `[seller.smtp]` is a WARNING, not fatal: the
///      operator can still issue invoices, auto-email just won't fire.
///
/// Dev/test builds enforce NOTHING (any identity, creds may be absent,
/// SMTP silent) — the dev loop is unchanged.
///
/// All inputs are injected (not read inside) so the decision logic is
/// unit-testable without a keychain, a `HOME`, or a prod build.
pub(crate) fn sanity_check_environment(
    is_production: bool,
    expected_identity: Option<(&str, &str)>,
    seller_tax_number: Option<&str>,
    nav_creds_present: bool,
    first_launch_acknowledged: bool,
    smtp_configured: bool,
) -> SanityReport {
    let mut report = SanityReport {
        fatal: None,
        warnings: Vec::new(),
    };
    if !is_production {
        // Dev/test: no enforcement. The caller logs the (dev) group line.
        return report;
    }

    let tenant_name = expected_identity.map(|(t, _)| t).unwrap_or("prod");

    // A. seller.toml identity consistency.
    if let Some((_, expected_tax)) = expected_identity {
        match seller_tax_number {
            Some(tax) if tax == expected_tax => {
                tracing::info!(
                    tax_number = tax,
                    "sanity (A): seller.toml identity matches the documented prod entity"
                );
            }
            Some(other) => {
                let lines = [
                    format!("❌ FATAL: PRODUCTION build expects seller.toml tax_number {expected_tax} (Áben Consulting Kft.)"),
                    format!("            but found {other}. Refusing to start."),
                    "   This is hülye-biztos protection: a prod binary must only run against the documented prod identity.".to_string(),
                    format!("   Either: fix seller.toml at ~/.aberp/{tenant_name}/seller.toml, OR"),
                    "   rebuild without --features production for dev use.".to_string(),
                    String::new(),
                    format!("❌ VÉGZETES: az ÉLES build a(z) {expected_tax} adószámot várja a seller.toml-ban (Áben Consulting Kft.),"),
                    format!("            de {other} szerepel. Az indítás megtagadva."),
                    "   Ez hülye-biztos védelem: éles bináris kizárólag a dokumentált éles identitással futhat.".to_string(),
                    format!("   Vagy: javítsd a seller.toml-t itt: ~/.aberp/{tenant_name}/seller.toml, VAGY"),
                    "   fordítsd újra a --features production kapcsoló nélkül fejlesztői használatra.".to_string(),
                ];
                report.fatal = Some(lines.join("\n"));
            }
            None => {
                tracing::info!(
                    "sanity (A): seller.toml absent / identity-incomplete — deferring to the \
                     NeedsSellerConfig wizard (not fatal)"
                );
            }
        }
    }

    // B. NAV credentials present (or legitimately in first-launch).
    if nav_creds_present {
        tracing::info!("sanity (B): NAV credentials present in keychain");
    } else if first_launch_acknowledged {
        let lines = [
            "❌ FATAL: PRODUCTION build can't find NAV credentials in keychain.".to_string(),
            "   The first-launch ceremony was completed previously but the keychain entries are gone.".to_string(),
            format!("   Either: re-run the first-launch wizard (clear ~/.aberp/{tenant_name}/.first-launch-acknowledged), OR"),
            "   restore the keychain entries.".to_string(),
            String::new(),
            "❌ VÉGZETES: az ÉLES build nem találja a NAV hitelesítő adatokat a kulcstartóban.".to_string(),
            "   A first-launch ceremónia korábban lezárult, de a kulcstartó-bejegyzések eltűntek.".to_string(),
            format!("   Vagy: futtasd újra a first-launch varázslót (töröld: ~/.aberp/{tenant_name}/.first-launch-acknowledged), VAGY"),
            "   állítsd vissza a kulcstartó-bejegyzéseket.".to_string(),
        ];
        // Prefer the first fatal (A) if it already fired — the operator
        // fixes identity first, reboots, then sees this if still broken.
        if report.fatal.is_none() {
            report.fatal = Some(lines.join("\n"));
        }
    } else {
        tracing::info!(
            "sanity (B): NAV credentials absent and first-launch not yet acknowledged — the \
             first-launch wizard will populate them (not fatal)"
        );
    }

    // C. SMTP configured (warning only).
    if smtp_configured {
        tracing::info!("sanity (C): [seller.smtp] is configured");
    } else {
        report.warnings.push(
            "[seller.smtp] is not configured — invoices can still be issued, but auto-email \
             will not fire. Configure SMTP via Maintenance → Tenants to enable delivery. / \
             Az [seller.smtp] nincs beállítva — a számlák kiállíthatók, de az automatikus \
             e-mail nem indul el. Állítsd be az SMTP-t a Karbantartás → Bérlők menüben."
                .to_string(),
        );
    }

    report
}

pub fn run(args: &ServeArgs) -> Result<()> {
    // S165 / deliverable #5 — hülye-biztos cross-stream guard. Runs
    // FIRST, before the binary-hash thread, keychain, or DB are touched,
    // so a mismatched launch dies instantly with a remediation hint.
    // `args.tenant` is the authoritative tenant the server runs as (the
    // launchers set ABERP_TENANT, aberp-ui forwards it as `--tenant`).
    // The prod/test choice is COMPILE-TIME (`build_profile`), so a dev
    // binary physically cannot run as tenant=prod and vice versa.
    guard_tenant_matches_build(&args.tenant);

    // S165 / deliverable #3 — one-shot boot banner naming the NAV
    // environment this build talks to. Loud + colourised on a real
    // terminal so the operator can never confuse a PROD launch for a
    // dev one. Emitted to stderr (stdout carries the handshake line).
    print_boot_banner(&args.tenant);

    let _span = tracing::info_span!(
        "serve",
        tenant = %args.tenant,
        port = args.port,
        db = %args.db.display(),
    )
    .entered();

    // PR-46α.1 / session-62-fix — explicit step-entry log emits so a
    // hang at any boot step surfaces in the SPA's loading pane (via
    // recent_logs) with a name. Pre-fix, the only operator-visible
    // emit between subprocess spawn and the cert-ready log was the
    // background-thread binary-hash completion — which made a hung
    // foreground boot indistinguishable from a missing-handshake
    // emit. Step markers below name what step is in flight; the
    // LAST one logged before a stall is the suspect.
    tracing::info!("boot step: spawning background binary-hash compute");

    // PR-45a / session-61 — kick off the binary-hash compute FIRST,
    // before any other boot work. On a cold-cache debug build this
    // read+hash takes 5-10s; doing it on a background OS thread lets
    // the listener bind + handshake fire while the hash is still
    // crunching. Handlers block on `BinaryHashHandle::wait` if they
    // beat the background thread to the finish line (vanishingly
    // unlikely once the SPA finishes its initial /health probe).
    let binary_hash_handle = BinaryHashHandle::start_background();

    // 1. Resolve tenant id + load session token from the keychain.
    tracing::info!("boot step: resolving tenant id");
    let tenant = TenantId::new(args.tenant.clone()).ok_or_else(|| {
        anyhow!(
            "--tenant value '{}' is empty or has a null byte",
            args.tenant
        )
    })?;
    // PR-46α.1 / session-62-fix — explicit step-entry log so a
    // macOS keychain ACL prompt blocking `entry.get_password()` is
    // visible at the operator-facing layer. The keychain re-prompts
    // any time the binary signature changes (e.g. a rebuild); the
    // prompt window may be hidden behind the Tauri window and the
    // operator can't tell what they're waiting for.
    tracing::info!(
        "boot step: reading session token from OS keychain (may prompt for keychain access)"
    );
    let session_token = {
        let _s = tracing::info_span!("serve.session_token").entered();
        load_or_create_session_token(&args.tenant)?
    };

    // PR-44ζ / session-59 — load the NAV credentials at startup so the
    // `POST /invoices/issue` mutation route can derive a per-request
    // `Actor` without paying keychain latency on every issuance. The
    // only field we stash is `login()` (non-secret); the secret bytes
    // are dropped when this scope exits.
    //
    // PR-46α / session-62 — pre-PR-46α a missing keychain entry exited
    // the backend non-zero, which made the desktop window flash blank
    // (post-PR-45a: the Tauri shell rendered an unrecoverable Failed
    // pane). Now: a `KeychainItemMissing` variant transitions the
    // backend into the `NeedsSetup` boot state — the listener still
    // binds, the handshake still fires (with `state=needs-setup`
    // suffix), and the new `POST /api/setup-nav-credentials` route
    // lets the SPA's first-run wizard populate the four artifacts
    // without any terminal interaction. Every OTHER credential failure
    // (locked keychain, permission denied, etc.) still loud-fails per
    // CLAUDE.md rule 12 — those are operator-triage situations, not
    // first-run setup situations.
    // PR-46α.1 / session-62-fix — same prompt-warning posture as the
    // session_token step above. PR-57 / session-77: the four NAV
    // artifacts now live in ONE keychain item (`nav_credentials_blob`),
    // so the boot path is ONE `get_password` call → ONE potential ACL
    // prompt on a freshly-rebuilt binary (down from four pre-PR-57).
    // The first boot after applying PR-57 on an installation with the
    // four legacy entries still present additionally reads each of
    // those once to migrate; subsequent boots take the blob-only path.
    tracing::info!(
        "boot step: reading NAV credentials blob from OS keychain (may prompt for keychain access; \
         legacy 4-item migration on first launch after PR-57)"
    );
    let initial_boot_state = {
        let _s = tracing::info_span!("serve.nav_credentials").entered();
        match NavCredentials::load_from_keychain(&args.tenant) {
            Ok(creds) => {
                // PR-51 / session-71 — NAV creds present; the second
                // gate is the per-tenant seller.toml. A missing or
                // identity-incomplete file transitions to
                // NeedsSellerConfig so the SPA can fire its wizard
                // INSTEAD OF letting the operator hit the route
                // surface and get a typed `missing_seller_config` 400
                // hours later.
                derive_initial_boot_state_with_seller_check(creds.login().to_string(), &args.tenant)
            }
            Err(NavTransportError::KeychainItemMissing { item, .. }) => {
                tracing::warn!(
                    item = item,
                    "NAV credential missing from OS keychain — entering needs-setup boot state; \
                     SPA first-run wizard will populate via POST /api/setup-nav-credentials"
                );
                ServeBootState::NeedsSetup
            }
            Err(other) => {
                return Err(anyhow!(other)
                    .context("load NAV credentials from OS keychain for actor derivation"));
            }
        }
    };

    // Session-149 — read the SMTP password into the in-process cache
    // NOW, while we are still inside the boot keychain-read burst
    // (session token → NAV blob → SMTP password). Doing it here means
    // the OS sees one contiguous prompt burst on a freshly-rebuilt
    // binary, so the operator's Always-Allow consolidates and no SMTP
    // prompt surprises them later (e.g. opening Maintenance → Tenants).
    // Skips the read silently if `[seller.smtp]` is absent; never
    // hard-fails boot on a missing/locked SMTP item (see SecretsCache).
    tracing::info!(
        "boot step: reading SMTP password from OS keychain (may prompt for keychain access if \
         [seller.smtp] is configured)"
    );
    let secrets_cache = {
        let _s = tracing::info_span!("serve.smtp_password").entered();
        match setup_seller_info::seller_toml_path_for_tenant(&args.tenant) {
            Ok(path) => SecretsCache::init_at_boot(&args.tenant, &path),
            Err(e) => {
                tracing::warn!(
                    error = %format!("{e:#}"),
                    "could not resolve seller.toml path at boot — SMTP password cache left empty"
                );
                SecretsCache::empty()
            }
        }
    };

    // S166 / prod-prep PR #2 — the SECOND refuse-to-start guard pass.
    // `guard_tenant_matches_build` (above) cross-checked the build vs the
    // tenant NAME; this cross-checks the build vs the on-disk + keychain
    // ENVIRONMENT. Runs after the keychain-read burst so it reuses the
    // already-computed `initial_boot_state` (NeedsSetup ⟺ NAV creds
    // missing) — no second keychain read, no second ACL prompt. Prod
    // builds enforce; dev builds are a no-op (sanity_check_environment
    // returns an empty report).
    {
        let group = if build_profile::IS_PRODUCTION_BUILD {
            "boot step: sanity checks (prod)"
        } else {
            "boot step: sanity checks (dev)"
        };
        tracing::info!("{group}");
        let _s = tracing::info_span!("serve.sanity_checks").entered();
        let seller_path = setup_seller_info::seller_toml_path_for_tenant(&args.tenant).ok();
        let seller_tax_number = seller_path
            .as_ref()
            .and_then(|p| setup_seller_info::read_seller_identity(p).ok().flatten())
            .map(|id| id.tax_number);
        let smtp_configured = seller_path
            .as_ref()
            .map(|p| matches!(smtp_config_mod::read_smtp_config(p), Ok(Some(_))))
            .unwrap_or(false);
        let nav_creds_present = !matches!(initial_boot_state, ServeBootState::NeedsSetup);
        let first_launch_acknowledged = crate::first_launch::is_acknowledged(&args.tenant);

        let report = sanity_check_environment(
            build_profile::IS_PRODUCTION_BUILD,
            build_profile::expected_tenant_identity(),
            seller_tax_number.as_deref(),
            nav_creds_present,
            first_launch_acknowledged,
            smtp_configured,
        );
        for w in &report.warnings {
            tracing::warn!("sanity check warning: {w}");
        }
        if let Some(msg) = report.fatal {
            eprintln!("{msg}");
            std::process::exit(1);
        }

        // S171 / PR-171 — upgrade-snapshot check. If the operator ran
        // `tools/snapshot-prod.sh` before this upgrade, a
        // `.upgrade-snapshot.toml` sits alongside `seller.toml` carrying
        // the pre-upgrade `[seller.smtp]` + `[seller.numbering]`
        // sections; we compare against the current seller.toml and
        // refuse to start on drift. See `crate::upgrade_snapshot` for
        // the trust-code-not-operator rationale and the four-scenario
        // unit tests.
        if let Some(seller_path) = seller_path.as_ref() {
            let snapshot_path = seller_path.with_file_name(".upgrade-snapshot.toml");
            let _s = tracing::info_span!("serve.upgrade_snapshot_check").entered();
            match upgrade_snapshot::check_upgrade_snapshot(seller_path, &snapshot_path) {
                Ok(upgrade_snapshot::Outcome::Absent) => {
                    tracing::info!(
                        "upgrade-snapshot check: no .upgrade-snapshot.toml present — skipping"
                    );
                }
                Ok(upgrade_snapshot::Outcome::Matches) => {
                    use time::format_description::well_known::Rfc3339;
                    use time::OffsetDateTime;
                    let ts = OffsetDateTime::now_utc()
                        .format(&Rfc3339)
                        .unwrap_or_else(|_| "verified".to_string());
                    // Sanitize the timestamp for use in a filename: keep
                    // ASCII alphanumerics + `-`, replace everything else
                    // (the `:` in RFC3339) with `-`.
                    let safe_ts: String = ts
                        .chars()
                        .map(|c| {
                            if c.is_ascii_alphanumeric() || c == '-' {
                                c
                            } else {
                                '-'
                            }
                        })
                        .collect();
                    if let Err(e) = upgrade_snapshot::mark_verified(&snapshot_path, &safe_ts) {
                        tracing::warn!(
                            error = %format!("{e:#}"),
                            "upgrade-snapshot matched but rename failed; \
                             boot continues — next boot will re-check (harmless)"
                        );
                    } else {
                        tracing::info!(
                            "upgrade-snapshot check: matched current seller.toml — boot proceeding"
                        );
                    }
                }
                Ok(upgrade_snapshot::Outcome::Mismatch { deltas }) => {
                    use time::format_description::well_known::Rfc3339;
                    use time::OffsetDateTime;
                    let detected_at = OffsetDateTime::now_utc()
                        .format(&Rfc3339)
                        .unwrap_or_else(|_| "unknown".to_string());
                    // Best-effort audit append BEFORE the exit so the
                    // divergence is permanently hash-chained even if
                    // the operator later resolves it by mv-ing the
                    // snapshot file. A failure to append is logged but
                    // does NOT mask the refusal-to-boot.
                    if let Err(e) = record_upgrade_snapshot_mismatch_audit(
                        &args.db,
                        &args.tenant,
                        &binary_hash_handle,
                        &deltas,
                        &detected_at,
                    ) {
                        tracing::warn!(
                            error = %format!("{e:#}"),
                            "could not write UpgradeSnapshotMismatch audit entry; refusing boot anyway"
                        );
                    }
                    let msg = upgrade_snapshot::format_bilingual_error(&deltas, &snapshot_path);
                    eprintln!("{msg}");
                    std::process::exit(1);
                }
                Err(e) => {
                    // Parse failure on the snapshot file — surface and
                    // continue. The check is opt-in (operator must have
                    // run snapshot-prod.sh), so a malformed file is the
                    // operator's responsibility; loud-fail-on-parse
                    // would hold the binary hostage to a bad file.
                    tracing::warn!(
                        error = %format!("{e:#}"),
                        "upgrade-snapshot check errored — treating as Absent"
                    );
                }
            }
        }
    }

    // PR-73a / hotfix — run the idempotent billing schema migrations
    // at boot so an existing pre-PR-73 tenant DB picks up the five
    // `bank_account_*` columns on `invoice` before the first
    // `list_invoices` request runs `load_invoice_bank_snapshot_in_tx`.
    // Pre-PR-73a the migration only ran lazily inside the issue path's
    // `pre_tx_setup` (issue_invoice / issue_storno / issue_modification);
    // a read-only operator who opened the SPA without issuing first hit
    // a 500 from the bank-snapshot SELECT against the un-migrated
    // schema. `ADD COLUMN IF NOT EXISTS` is idempotent so re-running on
    // every boot costs nothing on already-migrated DBs.
    tracing::info!("boot step: ensuring billing schema (idempotent migrations)");
    {
        let _s = tracing::info_span!("serve.ensure_billing_schema").entered();
        if let Some(parent) = args.db.parent() {
            std::fs::create_dir_all(parent).with_context(|| {
                format!(
                    "create parent directory {} for tenant DuckDB",
                    parent.display()
                )
            })?;
        }
        let mut billing_store = DuckDbBillingStore::open(&args.db).with_context(|| {
            format!(
                "open billing DuckDB at {} for boot migration",
                args.db.display()
            )
        })?;
        billing_store
            .ensure_schema()
            .context("ensure billing schema at serve boot")?;
    }

    // PR-91 — pin the products table schema at boot for the same
    // read-only-cold-start reason as the partners + billing tables
    // (PR-73a). Idempotent CREATE TABLE IF NOT EXISTS so re-runs on
    // already-migrated DBs cost nothing.
    {
        let _s = tracing::info_span!("serve.ensure_products_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for products boot migration",
                args.db.display()
            )
        })?;
        products::ensure_schema(&conn).context("ensure products schema at serve boot")?;
    }

    // S231 / PR-227 / ADR-0061 — pin the inventory schema at boot
    // (extends products with stock_qty/min_stock/bin_location/
    // last_movement_at cache columns + creates the stock_movements
    // append-only ledger). Same idempotent ALTER ADD COLUMN IF NOT
    // EXISTS / CREATE TABLE IF NOT EXISTS posture as products /
    // ap_invoice / restored_invoice — re-runs on migrated DBs cost
    // nothing. MUST run AFTER the products migration above because
    // the ALTER targets that table.
    {
        let _s = tracing::info_span!("serve.ensure_inventory_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for inventory boot migration",
                args.db.display()
            )
        })?;
        aberp_inventory::ensure_schema(&conn).context("ensure inventory schema at serve boot")?;
    }

    // S232 / PR-228 / ADR-0062 — pin the work-orders schema at boot
    // (creates work_orders + boms + routings tables). Same idempotent
    // CREATE TABLE IF NOT EXISTS posture as the inventory migration
    // above. MUST run AFTER the products migration (BOM rows reference
    // products by id even though no FK is declared per [[no-sql-specific]]).
    {
        let _s = tracing::info_span!("serve.ensure_work_orders_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for work-orders boot migration",
                args.db.display()
            )
        })?;
        aberp_work_orders::ensure_schema(&conn)
            .context("ensure work-orders schema at serve boot")?;
    }

    // S233 / PR-229 / ADR-0063 — pin the QA-queue schema at boot
    // (creates qa_inspections table). Same idempotent posture as the
    // work-orders migration above. MUST run AFTER the work-orders
    // migration because the QA module references routing-op ids
    // (no FK is declared per [[no-sql-specific]]).
    {
        let _s = tracing::info_span!("serve.ensure_qa_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for qa boot migration",
                args.db.display()
            )
        })?;
        aberp_qa::ensure_schema(&conn).context("ensure qa schema at serve boot")?;
    }

    // S234 / PR-230 — pin the dispatches schema at boot, same posture
    // as the other Stage 3 Phase γ siblings (inventory / work-orders /
    // qa). The route layer also calls `ensure_schema` defensively so a
    // fresh DB + first route hit does not 500. No FK to `work_orders`
    // / `partners` / `invoice` per [[no-sql-specific]] — the
    // application-level eligibility gate in `aberp_dispatch::create_dispatch`
    // is the authoritative check.
    {
        let _s = tracing::info_span!("serve.ensure_dispatch_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for dispatch boot migration",
                args.db.display()
            )
        })?;
        aberp_dispatch::ensure_schema(&conn).context("ensure dispatch schema at serve boot")?;
    }

    // S236 / PR-230b — pin the `invoice_draft` schema at boot. Mirrors
    // the dispatch / WO / QA boot posture above. The route layer also
    // calls `ensure_schema` defensively so a fresh DB + first route hit
    // does not 500. The table backs the new `InvoiceState::Draft` SPA
    // surface; the BillingInvoiceSpawner writes here on
    // dispatches→Shipped.
    {
        let _s = tracing::info_span!("serve.ensure_invoice_draft_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for invoice_draft boot migration",
                args.db.display()
            )
        })?;
        invoice_draft::ensure_schema(&conn).context("ensure invoice_draft schema at serve boot")?;
    }

    // S177 / PR-177 — pin the ap_invoice (incoming AP-side mirror)
    // schema at boot, same posture as products + partners. The route
    // layer also calls `ensure_schema` defensively so a fresh DB +
    // first route hit does not 500.
    {
        let _s = tracing::info_span!("serve.ensure_ap_invoice_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for ap_invoice boot migration",
                args.db.display()
            )
        })?;
        incoming_invoices::ensure_schema(&conn)
            .context("ensure ap_invoice schema at serve boot")?;
    }

    // S180 / PR-180 — pin the `restored_invoice` schema at boot, same
    // posture as `ap_invoice`. The route layer also calls
    // `ensure_schema` defensively so a fresh DB + first wizard
    // invocation does not 500.
    {
        let _s = tracing::info_span!("serve.ensure_restored_invoice_schema").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for restored_invoice boot migration",
                args.db.display()
            )
        })?;
        restore_outgoing::ensure_schema(&conn)
            .context("ensure restored_invoice schema at serve boot")?;
    }

    // Session 152b — reconcile the audit-ledger mirror against the DB
    // at boot. The mirror (`<db>.audit.log`) is a derivable cache, not
    // a source of truth. If the operator nuked the DuckDB per the
    // dev-DB-disposable rule but left the mirror in place, the mirror
    // is now AHEAD of the fresh DB; pre-152b the first post-commit
    // `sync_mirror` 500'd ("mirror is ahead of DB"), skipping the NAV
    // XML write and cascading into a submit 500. Boot reconciliation
    // truncates the ahead mirror back to the DB's max seq (and handles
    // missing / behind / corrupt / hash-mismatch). Idempotent on a
    // healthy state. Per-write `sync_mirror` still loud-fails on
    // mid-process divergence — that IS a runtime bug.
    tracing::info!("boot step: reconciling audit-ledger mirror with DB (idempotent recovery)");
    {
        let _s = tracing::info_span!("serve.recover_audit_mirror").entered();
        let conn = Connection::open(&args.db).with_context(|| {
            format!(
                "open tenant DuckDB at {} for audit-ledger mirror recovery",
                args.db.display()
            )
        })?;
        aberp_audit_ledger::ensure_schema(&conn)
            .context("ensure audit-ledger schema at serve boot")?;
        let mirror_path = aberp_audit_ledger::mirror_path_for(&args.db);
        let action = aberp_audit_ledger::ensure_consistent_with_db(&conn, &mirror_path)
            .context("reconcile audit-ledger mirror with DB at serve boot")?;
        tracing::info!(?action, "audit-ledger mirror reconciled at boot");
    }

    // 2. Resolve / generate the loopback cert + key.
    tracing::info!("boot step: preparing serve-artifacts directory");
    let artifacts_dir = serve_artifacts_dir(&args.tenant)?;
    std::fs::create_dir_all(&artifacts_dir).with_context(|| {
        format!(
            "create serve artifacts directory at {}",
            artifacts_dir.display()
        )
    })?;
    let cert_path = artifacts_dir.join("loopback.crt.pem");
    let key_path = artifacts_dir.join("loopback.key.pem");
    let fingerprint_path = artifacts_dir.join("loopback.fingerprint.sha256");
    tracing::info!("boot step: ensuring loopback TLS cert + key (rcgen on first launch)");
    let (cert_pem, key_pem, fingerprint_hex) = {
        let _s = tracing::info_span!("serve.loopback_cert").entered();
        ensure_loopback_cert(&cert_path, &key_path, &fingerprint_path)?
    };
    tracing::info!(
        cert = %cert_path.display(),
        fingerprint = %fingerprint_hex,
        "loopback TLS certificate ready"
    );

    // 3. Build the rustls server config.
    tracing::info!("boot step: building rustls server config");
    let rustls_config = {
        let _s = tracing::info_span!("serve.rustls_config").entered();
        build_rustls_config(&cert_pem, &key_pem)?
    };

    // 4. Build the shared application state. `binary_hash` is the
    //    handle to the background compute kicked off at the top;
    //    handlers block on it if they need the hash before it
    //    resolves.
    //
    // PR-46α / session-62 — `boot_state` carries the (possibly
    // mutable) Ready / NeedsSetup discriminator. The setup route
    // takes the write lock when transitioning; every other handler
    // takes a read lock to either pull `operator_login` or reject
    // with 503 needs-setup.
    let state_token_at_print = initial_boot_state.state_token();
    // PR-209 / S213 — mint the shutdown token here so it's
    // available to BOTH `AppState` (cloned into every
    // dynamically-spawned NAV poll daemon) AND the
    // `ShutdownCoordinator` built inside the runtime block. Same
    // underlying token (CancellationToken is Arc<Inner> internally);
    // either side firing `cancel()` propagates to every clone.
    let shutdown_token_root = tokio_util::sync::CancellationToken::new();
    // S240 / PR-234 — empty registry created here so it can be cloned
    // into both `AppState` (for the dashboard handler) and the MES boot
    // path (which registers adapters into it after `start()` succeeds).
    let adapter_registry = Arc::new(std::sync::RwLock::new(AdapterRegistry::new()));
    let state = AppState {
        db_path: Arc::new(args.db.clone()),
        tenant,
        binary_hash: binary_hash_handle,
        session_token: Arc::new(session_token.clone()),
        boot_state: Arc::new(std::sync::RwLock::new(initial_boot_state)),
        secrets_cache,
        nav_poll_semaphore: Arc::new(tokio::sync::Semaphore::new(NAV_POLL_DAEMON_CONCURRENCY)),
        shutdown_token: shutdown_token_root.clone(),
        adapter_registry: adapter_registry.clone(),
    };

    // 5. Build the axum router. Clone the state first so the app-boot
    //    NAV poll daemon recovery (spawned inside the runtime below) has
    //    its own handle after `build_router` consumes `state`.
    let recovery_state = state.clone();
    let app = build_router(state);

    // 6. Build a tokio multi-thread runtime (the serve subcommand is
    //    long-running on a single operator workstation; a small
    //    worker pool is fine here).
    tracing::info!("boot step: building tokio multi-thread runtime");
    let runtime = {
        let _s = tracing::info_span!("serve.tokio_runtime").entered();
        tokio::runtime::Builder::new_multi_thread()
            .enable_all()
            .build()
            .context("build tokio multi-thread runtime for axum")?
    };

    // 7. Bind the TCP listener synchronously so we can read the
    //    kernel-assigned port BEFORE printing the handshake. Pre-
    //    PR-45a we passed `127.0.0.1:0` straight to `bind_rustls`,
    //    which made the handshake unparseable: the operator-visible
    //    line read `https://127.0.0.1:0/`, and the desktop shell's
    //    handshake parser had no way to learn the resolved port.
    tracing::info!(port = args.port, "boot step: binding loopback TCP listener");
    let bind_addr: SocketAddr = format!("127.0.0.1:{}", args.port)
        .parse()
        .with_context(|| {
            format!(
                "parse loopback socket address 127.0.0.1:{} (port out of range?)",
                args.port
            )
        })?;
    let listener = {
        let _s = tracing::info_span!("serve.tcp_bind").entered();
        TcpListener::bind(bind_addr).with_context(|| format!("bind TCP listener at {bind_addr}"))?
    };
    let resolved_addr = listener
        .local_addr()
        .context("read resolved local_addr from TCP listener")?;
    tracing::info!(
        bind = %resolved_addr,
        fingerprint = %fingerprint_hex,
        session_token_first8 = &session_token[..8.min(session_token.len())],
        "starting HTTPS loopback listener — present \
         `Authorization: Bearer <session_token>` to authenticated routes; \
         verify TLS cert against the SHA-256 fingerprint"
    );

    // PR-45a / session-61 — machine-parseable handshake line. The
    // Tauri shell's `handshake::parse` consumes the line as
    // whitespace-separated tokens (literal `READY`, a `SocketAddr`,
    // `sha256:<64-hex>`, and PR-46α-added optional `state=<token>`);
    // the addr token round-trips through `parse::<SocketAddr>()`
    // cleanly. The human-readable `aberp serve: …` line moved to the
    // tracing log above so an operator running the shell still sees
    // the resolved port in the forwarded stderr stream. A drift in
    // either side fails loudly at the SPA's handshake step rather
    // than silently mis-routing.
    //
    // PR-46α / session-62 — the trailing `state=<token>` token
    // exposes the boot lifecycle (Ready vs NeedsSetup) at the
    // handshake boundary so the Tauri shell can dispatch the SPA's
    // first-paint between the normal app and the first-run setup
    // wizard. Token values: `ready` | `needs-setup`. Missing token =
    // `ready` (backwards-compat with the PR-45a line shape for any
    // future-stable third-party reader; the parser tolerates absence).
    println!(
        "READY {} sha256:{} state={}",
        resolved_addr, fingerprint_hex, state_token_at_print
    );

    runtime.block_on(async move {
        // PR-209 / S213 — graceful-shutdown coordinator. Uses the
        // SAME token already minted at state-construction time
        // (`shutdown_token_root`) so post-issue NAV poll daemons
        // spawned via `state.shutdown_token.clone()` share the
        // cancellation signal with the boot-time daemons registered
        // here. The coordinator's `register` is the load-bearing
        // side — boot-time daemons whose JoinHandle is registered
        // get awaited during drain; post-issue daemons are not
        // registered (per-invoice ephemeral) but DO receive the
        // token, so they exit on cancellation even though the
        // coordinator doesn't track them by name.
        let mut coordinator = ShutdownCoordinator::from_token(shutdown_token_root.clone());

        // Session-161 — app-boot NAV poll daemon recovery. Scan the
        // audit ledger for invoices still in `Submitted` (NAV accepted,
        // no terminal ack yet) and re-spawn an indefinite poll daemon
        // for each. The audit trail is the truth; the daemon chases it.
        // Closing ABERP mid-poll and reopening tomorrow resumes the
        // chase. Best-effort: a scan failure logs and continues — the
        // operator can still poll manually. Runs BEFORE `serve()` so the
        // daemons are in flight as soon as the listener accepts.
        //
        // PR-209 / S213 — the boot-recovery FAN-OUT itself is wrapped
        // in ONE registered task (not per-invoice) so the coordinator
        // doesn't have to track 50 dynamic handles. The wrapper task
        // spawns one un-registered child per pending invoice; each
        // child's `run_nav_poll_daemon` receives the same shutdown
        // token, so cancellation still reaches every NAV poll loop.
        // The wrapper exits as soon as its fan-out completes (the
        // children outlive it — that's fine, the token reaches them
        // directly).
        let recovery_token = coordinator.token.clone();
        let recovery_for_task = recovery_state.clone();
        let recovery_handle = tokio::spawn(async move {
            match query_non_terminal_invoices(&recovery_for_task) {
                Ok(pending) => {
                    tracing::info!(
                        count = pending.len(),
                        "spawning NAV poll daemons for pending invoices"
                    );
                    for invoice_id in pending {
                        if recovery_token.is_cancelled() {
                            return;
                        }
                        let st = recovery_for_task.clone();
                        let child_token = recovery_token.clone();
                        tokio::spawn(async move {
                            match build_poll_daemon_inputs(&st, &invoice_id).await {
                                Ok(inputs) => {
                                    if let Err(e) = poll_ack::run_nav_poll_daemon(
                                        inputs,
                                        st.nav_poll_semaphore.clone(),
                                        child_token,
                                    )
                                    .await
                                    {
                                        tracing::warn!(
                                            invoice_id = %invoice_id,
                                            error = ?e,
                                            "boot-recovery NAV poll daemon failed"
                                        );
                                    }
                                }
                                Err(e) => tracing::warn!(
                                    invoice_id = %invoice_id,
                                    error = ?e,
                                    "boot-recovery could not build poll daemon inputs; skipping"
                                ),
                            }
                        });
                    }
                }
                Err(e) => tracing::warn!(
                    error = ?e,
                    "boot-recovery NAV poll daemon scan failed; continuing without recovery"
                ),
            }
        });
        coordinator.register("nav-poll-boot-recovery", recovery_handle);

        // S178 / PR-178 — AP-side auto-sync daemon. Mirrors the
        // outgoing-side NAV poll daemon's spawn-and-forget posture;
        // ticks 30s after boot then every 30 min. Builds its own
        // `CycleInputs` on every tick (so a mid-run NAV credential
        // rotation is picked up at the next cadence without a
        // restart). The closure clones state into the task so the
        // outer `recovery_state` move is safe.
        //
        // PR-209 / S213 — registered with the shutdown coordinator.
        // `ap_sync::run_daemon_forever` accepts the cancellation
        // token; a shutdown mid-cadence-sleep exits within ms instead
        // of waiting 30 minutes for the next tick.
        {
            let st = recovery_state.clone();
            let ap_sync_token = coordinator.token.clone();
            let ap_sync_handle = tokio::spawn(async move {
                let st = st;
                ap_sync::run_daemon_forever(move || {
                    let operator_login = match st.boot_state.read() {
                        Ok(guard) => match &*guard {
                            ServeBootState::Ready { operator_login } => operator_login.clone(),
                            other => {
                                return Err(anyhow!(
                                    "AP sync daemon waiting on boot_state ({}); skipping tick",
                                    other.state_token()
                                ));
                            }
                        },
                        Err(e) => return Err(anyhow!("boot_state RwLock poisoned: {e}")),
                    };
                    // Build a blocking-style call inside a closure
                    // that returns `Result<CycleInputs>` — the daemon
                    // helper awaits the daemon-internal work, but the
                    // input-building itself is synchronous (keychain
                    // read + seller.toml read + endpoint pick).
                    let binary_hash = st
                        .binary_hash
                        .wait()
                        .context("await background binary hash for AP sync daemon")?;
                    let credentials = NavCredentials::load_from_keychain(st.tenant.as_str())
                        .with_context(|| {
                            format!(
                                "load NAV credentials from OS keychain for tenant `{}` (AP sync daemon)",
                                st.tenant.as_str()
                            )
                        })?;
                    let supplier = supplier_from_seller_toml(st.tenant.as_str()).map_err(|e| {
                        anyhow!(
                            "load supplier identity for AP sync daemon (tenant `{}`): {:?}",
                            st.tenant.as_str(),
                            e
                        )
                    })?;
                    let parsed = nav_xml::parse_hungarian_tax_number(&supplier.tax_number)
                        .map_err(|e| {
                            anyhow!(
                                "parse supplier tax number `{}` for AP sync daemon: {:?}",
                                supplier.tax_number,
                                e
                            )
                        })?;
                    let endpoint = build_profile::nav_endpoint();
                    build_profile::assert_endpoint_allowed(endpoint)?;
                    let artifacts_dir = ap_artifacts_dir(st.tenant.as_str())?;
                    Ok(ap_sync::CycleInputs {
                        db_path: (*st.db_path).clone(),
                        tenant: st.tenant.clone(),
                        binary_hash,
                        operator_login,
                        ap_artifacts_dir: artifacts_dir,
                        tax_number_8: parsed.taxpayer_id,
                        endpoint,
                        credentials,
                    })
                }, ap_sync_token)
                .await;
            });
            coordinator.register("ap-sync", ap_sync_handle);
        }

        // PR-216 / S218 — one-shot buyer-snapshot backfill for
        // `restored_invoice` rows the S180 wizard mirrored before
        // PR-216's S196-side write-back landed, OR rows whose S196
        // `queryInvoiceData` fetch failed mid-cycle (transport
        // glitch, NAV outage). Scans for rows with NULL customer_name
        // and re-fetches `queryInvoiceData OUTBOUND` to populate the
        // buyer label IN-ROW. Trust-code-not-operator: backfill runs
        // automatically on boot — Ervin's 14 already-imported prod
        // rows from 2026-06-01 light up without an operator action.
        //
        // Spawned on the tokio pool, cancel-aware. Per-row failures
        // are warn-and-continue; the row stays NULL and the next boot
        // will retry. Idempotent: a re-run after a successful pass
        // finds 0 rows and returns immediately. Registered with the
        // shutdown coordinator so a Tauri close mid-scan exits within
        // ms.
        {
            let st = recovery_state.clone();
            let backfill_token = coordinator.token.clone();
            let backfill_handle = tokio::spawn(async move {
                let inputs = {
                    let credentials =
                        match NavCredentials::load_from_keychain(st.tenant.as_str()) {
                            Ok(c) => c,
                            Err(e) => {
                                tracing::info!(
                                    error = ?e,
                                    "S218: buyer-backfill skipped — no NAV credentials in \
                                     keychain (first-boot tenant); next launch retries"
                                );
                                return;
                            }
                        };
                    let supplier = match supplier_from_seller_toml(st.tenant.as_str()) {
                        Ok(s) => s,
                        Err(e) => {
                            tracing::warn!(
                                error = ?e,
                                "S218: buyer-backfill skipped — could not load supplier \
                                 identity from seller.toml"
                            );
                            return;
                        }
                    };
                    let parsed = match nav_xml::parse_hungarian_tax_number(&supplier.tax_number) {
                        Ok(p) => p,
                        Err(e) => {
                            tracing::warn!(
                                error = ?e,
                                "S218: buyer-backfill skipped — could not parse supplier \
                                 tax number"
                            );
                            return;
                        }
                    };
                    let endpoint = build_profile::nav_endpoint();
                    if let Err(e) = build_profile::assert_endpoint_allowed(endpoint) {
                        tracing::warn!(
                            error = ?e,
                            "S218: buyer-backfill skipped — NAV endpoint not allowed"
                        );
                        return;
                    }
                    // PR-217 / S220 — resolve the binary hash so the
                    // cycle-completion audit entry can be appended.
                    // `wait()` blocks at most until the background
                    // hash-of-self task completes; on the boot path
                    // it has been running since `serve::run`'s start
                    // and is typically already resolved.
                    let binary_hash = match st.binary_hash.wait() {
                        Ok(h) => h,
                        Err(e) => {
                            tracing::warn!(
                                error = ?e,
                                "S218: buyer-backfill skipped — binary hash not available"
                            );
                            return;
                        }
                    };
                    restore_outgoing::BackfillInputs {
                        db_path: (*st.db_path).clone(),
                        tenant: st.tenant.clone(),
                        tax_number_8: parsed.taxpayer_id,
                        endpoint,
                        credentials,
                        binary_hash,
                    }
                };
                let _ = restore_outgoing::run_buyer_backfill_once(inputs, backfill_token).await;
            });
            coordinator.register("restore-buyer-backfill", backfill_handle);
        }

        // S210 / PR-204 — quote-intake daemon. Opt-in via either the
        // `ABERP_QUOTE_INTAKE_ENABLED=true` env var (S210, ops escape
        // hatch) OR the operator-typed `[quote_intake]` section in
        // seller.toml + a keychain token (S211, SPA-driven). Precedence
        // is env > toml+keychain > dormant. When the operator changes
        // the toml config via the SPA the daemon does NOT hot-reload
        // (S211 conservative-choice) — the change takes effect on the
        // next `aberp serve` boot.
        //
        // Refuse-to-start: `ENABLED=true` (env) OR `enabled=true`
        // (toml) with missing URL / TOKEN aborts the boot rather than
        // spawn a daemon that polls a wrong URL forever. Per
        // [[trust-code-not-operator]] and brief §8.
        {
            let st = recovery_state.clone();
            let cfg_result: std::result::Result<QuoteIntakeConfig, QuoteIntakeError> =
                match QuoteIntakeConfig::from_env() {
                    Ok(c) => Ok(c),
                    Err(QuoteIntakeError::Disabled) => {
                        // Env-var path off; try toml + keychain.
                        let seller_path = setup_seller_info::seller_toml_path_for_tenant(
                            st.tenant.as_str(),
                        )
                        .context("resolve seller.toml path for quote-intake boot")?;
                        let toml_cfg = crate::quote_intake_config::read_quote_intake_config(
                            &seller_path,
                        )
                        .map_err(|e| anyhow!("read [quote_intake] from seller.toml: {e:#}"))?;
                        match toml_cfg {
                            None => Err(QuoteIntakeError::Disabled),
                            Some(c) if !c.enabled => Err(QuoteIntakeError::Disabled),
                            Some(c) => {
                                let base_url = c.base_url.clone().ok_or_else(|| {
                                    QuoteIntakeError::Config(
                                        "[quote_intake] enabled=true but base_url is missing"
                                            .to_string(),
                                    )
                                })?;
                                let token = crate::quote_intake_credentials::read_token(
                                    st.tenant.as_str(),
                                )
                                .map_err(|e| {
                                    QuoteIntakeError::Config(format!(
                                        "[quote_intake] enabled=true but keychain token \
                                         unreadable: {e}"
                                    ))
                                })?;
                                QuoteIntakeConfig::from_toml_and_keychain_parts(
                                    base_url,
                                    token,
                                    c.poll_interval_secs,
                                )
                            }
                        }
                    }
                    Err(other) => Err(other),
                };
            match cfg_result {
                Ok(cfg) => {
                    let operator_login = match st.boot_state.read() {
                        Ok(guard) => match &*guard {
                            ServeBootState::Ready { operator_login } => operator_login.clone(),
                            _ => "boot".to_string(),
                        },
                        Err(_) => "boot".to_string(),
                    };
                    let binary_hash = st
                        .binary_hash
                        .wait()
                        .context("await background binary hash for quote-intake daemon")?;
                    let deps = QuoteIntakeDeps {
                        db_path: (*st.db_path).clone(),
                        tenant: st.tenant.clone(),
                        binary_hash,
                        operator_login,
                        default_currency: Currency::Huf,
                    };
                    match QuoteIntakeService::new(cfg, deps) {
                        Ok(service) => {
                            tracing::info!(
                                cadence_secs = service.poll_interval().as_secs(),
                                "spawning quote-intake daemon (S210 / PR-204)"
                            );
                            // PR-209 / S213 — registered with the
                            // shutdown coordinator; cancellation
                            // races the cadence sleep so a Tauri
                            // close exits within ms.
                            let quote_intake_token = coordinator.token.clone();
                            let quote_intake_handle = tokio::spawn(async move {
                                service.run_daemon_forever(quote_intake_token).await;
                            });
                            coordinator.register("quote-intake", quote_intake_handle);
                        }
                        Err(e) => {
                            return Err(anyhow!(
                                "quote-intake daemon refused to start: {e:#}"
                            ));
                        }
                    }
                }
                Err(QuoteIntakeError::Disabled) => {
                    tracing::info!(
                        "quote-intake daemon disabled (no env vars and \
                         [quote_intake].enabled != true); skipping spawn"
                    );
                }
                Err(e) => {
                    return Err(anyhow!("quote-intake config error: {e:#}"));
                }
            }
        }

        // S229 / PR-225 — Stage 3 manufacturing-adapter framework
        // boot (ADR-0060 Phase β). The barcode scanner adapter binds
        // a TCP listener and emits `CanonicalEvent::ScanReceived`
        // events into the audit ledger via the per-adapter
        // ledger-writer task. Opt-in via the
        // `ABERP_BARCODE_SCANNER_ENABLED=true` env var; same posture
        // as quote-intake S210 — keychain / seller.toml integration
        // is deferred to a follow-up PR per the
        // [[seller-toml-write-invariant]] family preservation
        // discipline.
        //
        // DoS bounds (`max_payload_len`, `max_concurrent_connections`)
        // stay at compiled defaults per [[trust-code-not-operator]] —
        // env-var knobs are scanner_id + host + port only.
        {
            let operator_login = match recovery_state.boot_state.read() {
                Ok(guard) => match &*guard {
                    ServeBootState::Ready { operator_login } => operator_login.clone(),
                    _ => "boot".to_string(),
                },
                Err(_) => "boot".to_string(),
            };
            let binary_hash = recovery_state
                .binary_hash
                .wait()
                .context("await background binary hash for MES barcode-scanner boot")?;
            let mes_deps = crate::mes_boot::MesBootDeps {
                db_path: (*recovery_state.db_path).clone(),
                tenant: recovery_state.tenant.clone(),
                binary_hash,
                operator_login,
                session_id: Ulid::new().to_string(),
            };
            match crate::mes_boot::boot_mes_adapters(
                mes_deps,
                coordinator.token.clone(),
                recovery_state.adapter_registry.clone(),
            )
            .await
            {
                Ok(Some(spawned)) => {
                    for (label, handle) in spawned.handles {
                        coordinator.register(label, handle);
                    }
                }
                Ok(None) => {} // disabled — already logged inside boot_mes_adapters
                Err(e) => {
                    return Err(anyhow!("MES adapter boot failed: {e:#}"));
                }
            }
        }

        let config = RustlsConfig::from_der(rustls_config.0, rustls_config.1)
            .await
            .context("build axum-server RustlsConfig")?;

        // PR-209 / S213 — graceful-shutdown wiring. axum-server's
        // `Handle::graceful_shutdown(None)` stops accepting new
        // connections and lets in-flight requests drain; we then
        // call the coordinator's `shutdown(timeout)` to fan
        // cancellation out to every registered daemon, write ONE
        // `DaemonShutdownCompleted` audit row, log the result, and
        // force-exit. The process MUST exit after this — any
        // un-registered tokio task would otherwise hold it alive
        // forever, which is exactly the bug PR-209 closes.
        let axum_handle = axum_server::Handle::new();
        let signal_axum_handle = axum_handle.clone();
        let signal_token = coordinator.token.clone();

        // Listen for ctrl_c (terminal launch) OR SIGTERM (Tauri
        // close handler routes window-close → child SIGTERM via the
        // `Child::kill` upgrade landed in `apps/aberp-ui/src/
        // backend.rs`). The first signal to arrive wins the race;
        // the resulting trigger string flows into the audit payload.
        let signal_listener: tokio::task::JoinHandle<&'static str> = tokio::spawn(async move {
            #[cfg(unix)]
            {
                use tokio::signal::unix::{signal, SignalKind};
                let mut sigterm = match signal(SignalKind::terminate()) {
                    Ok(s) => s,
                    Err(e) => {
                        tracing::warn!(error = %e, "could not install SIGTERM handler; \
                             relying on ctrl_c only");
                        // Fall back to ctrl_c-only: install a
                        // never-firing future for the SIGTERM arm.
                        let trigger = tokio::signal::ctrl_c()
                            .await
                            .map(|_| "ctrl-c")
                            .unwrap_or("ctrl-c-error");
                        signal_token.cancel();
                        signal_axum_handle.graceful_shutdown(Some(Duration::from_secs(2)));
                        return trigger;
                    }
                };
                let mut sighup = signal(SignalKind::hangup()).ok();
                let trigger = tokio::select! {
                    res = tokio::signal::ctrl_c() => {
                        if let Err(e) = res {
                            tracing::warn!(error = %e, "ctrl_c listener errored");
                        }
                        "ctrl-c"
                    }
                    _ = sigterm.recv() => "sigterm",
                    _ = async {
                        match sighup.as_mut() {
                            Some(s) => { s.recv().await; }
                            None => std::future::pending::<()>().await,
                        }
                    } => "hangup",
                };
                tracing::info!(trigger, "shutdown signal received; draining daemons");
                signal_token.cancel();
                signal_axum_handle.graceful_shutdown(Some(Duration::from_secs(2)));
                trigger
            }
            #[cfg(not(unix))]
            {
                let _ = tokio::signal::ctrl_c().await;
                tracing::info!(trigger = "ctrl-c", "shutdown signal received; draining daemons");
                signal_token.cancel();
                signal_axum_handle.graceful_shutdown(Some(Duration::from_secs(2)));
                "ctrl-c"
            }
        });

        let serve_result = axum_server::from_tcp_rustls(listener, config)
            .handle(axum_handle)
            .serve(app.into_make_service())
            .await
            .context("axum_server::from_tcp_rustls(...).serve(...)");

        // Reach the trigger label. If the signal listener has fired
        // (the common path — serve only returns AFTER graceful_shutdown
        // is called), join completes immediately. If serve returned for
        // another reason (axum error), the listener is still pending;
        // we abort it and treat the trigger as "axum-error" so the
        // audit row carries the truthful cause.
        let trigger: String = if signal_listener.is_finished() {
            signal_listener.await.map(|s| s.to_string()).unwrap_or_else(|e| {
                tracing::warn!(error = ?e, "signal listener task failed");
                "signal-task-error".to_string()
            })
        } else {
            signal_listener.abort();
            "axum-error".to_string()
        };

        // Drive the coordinator's drain pass. Returns within
        // `shutdown_timeout_from_env()` (default 5s) regardless of
        // daemon cooperation.
        let timeout = shutdown::shutdown_timeout_from_env();
        let shutdown_result = coordinator.shutdown(timeout).await;
        log_shutdown_result(&shutdown_result);
        write_shutdown_audit_entry(&recovery_state, &trigger, &shutdown_result);

        // The serve_result was captured BEFORE the drain so a hard
        // axum error still bubbles up via the runtime. We return
        // Ok(()) on the success path so the binary exits 0 cleanly.
        serve_result
    })?;

    Ok(())
}

/// PR-209 / S213 — log the coordinator's drain outcome. Pretty-formats
/// the timeout list so a `RUST_LOG=info` operator sees exactly which
/// daemon hung (or that nothing did) without having to re-parse JSON.
fn log_shutdown_result(result: &ShutdownResult) {
    if result.timeout_kills.is_empty() {
        tracing::info!(
            clean_exits = result.clean_exits,
            elapsed_ms = result.elapsed_ms,
            "graceful shutdown drained all daemons within timeout"
        );
    } else {
        tracing::warn!(
            clean_exits = result.clean_exits,
            timeout_kills = ?result.timeout_kills,
            elapsed_ms = result.elapsed_ms,
            "graceful shutdown drain timed out; named daemons will be \
             force-killed by process exit"
        );
    }
}

/// PR-209 / S213 — write the per-shutdown audit row. Best-effort: a
/// failure here logs loud but does NOT block the process exit — the
/// alternative would be a stuck process the operator can't kill, which
/// is the original bug. The audit chain is anchored at the next boot
/// via the existing boot-recovery scan.
fn write_shutdown_audit_entry(state: &AppState, trigger: &str, result: &ShutdownResult) {
    let binary_hash = match state.binary_hash.wait() {
        Ok(h) => h,
        Err(e) => {
            tracing::error!(
                error = ?e,
                "could not resolve binary hash for shutdown audit entry; skipping"
            );
            return;
        }
    };
    let operator_login = match state.boot_state.read() {
        Ok(guard) => match &*guard {
            ServeBootState::Ready { operator_login } => operator_login.clone(),
            _ => "shutdown".to_string(),
        },
        Err(_) => "shutdown".to_string(),
    };

    let payload = audit_payloads::DaemonShutdownCompletedPayload {
        idempotency_key: aberp_billing::IdempotencyKey::new().to_canonical_string(),
        trigger: trigger.to_string(),
        registered_daemons: {
            // Re-derive from the result: clean + timeout names sum
            // to the full registration. We don't have the clean
            // daemon names individually (the coordinator's API only
            // reports the timeout side by name to keep allocations
            // off the shutdown hot path), so we list the timeout
            // names + a placeholder count for the clean side. A
            // future PR can extend the API if a postmortem ever
            // needs per-clean-daemon names.
            let mut v = Vec::new();
            v.push(format!("clean_exits={}", result.clean_exits));
            for name in &result.timeout_kills {
                v.push((*name).to_string());
            }
            v
        },
        clean_exits: result.clean_exits as u64,
        timeout_kills: result
            .timeout_kills
            .iter()
            .map(|s| (*s).to_string())
            .collect(),
        elapsed_ms: result.elapsed_ms,
    };

    let db_path = (*state.db_path).clone();
    let tenant = state.tenant.clone();
    let actor = Actor::from_local_cli(Ulid::new().to_string(), &operator_login);
    let bytes = payload.to_bytes();

    let write_outcome = (|| -> Result<()> {
        let mut conn =
            Connection::open(&db_path).context("open tenant DuckDB for shutdown audit entry")?;
        aberp_audit_ledger::ensure_schema(&conn)
            .context("ensure audit-ledger schema for shutdown audit entry")?;
        let tx = conn
            .transaction()
            .context("begin DuckDB transaction for shutdown audit entry")?;
        let ledger_meta = aberp_audit_ledger::LedgerMeta::new(tenant.clone(), binary_hash);
        aberp_audit_ledger::append_in_tx(
            &tx,
            &ledger_meta,
            EventKind::DaemonShutdownCompleted,
            bytes,
            actor,
            None,
        )
        .context("audit_ledger::append_in_tx DaemonShutdownCompleted")?;
        tx.commit()
            .context("commit DuckDB transaction for shutdown audit entry")?;
        let mirror_path = aberp_audit_ledger::mirror_path_for(&db_path);
        let ledger = Ledger::open(&db_path, tenant, binary_hash)
            .context("open audit ledger after shutdown entry")?;
        ledger
            .sync_mirror(&mirror_path)
            .context("sync audit-ledger mirror after shutdown entry")?;
        Ok(())
    })();

    if let Err(e) = write_outcome {
        tracing::error!(error = ?e, "shutdown audit entry write failed; continuing exit");
    }
}

// ── Cert / key / fingerprint persistence ─────────────────────────────

/// If the persisted artifacts already exist, read them. Otherwise
/// generate a fresh self-signed cert via `rcgen`, persist all three
/// artifacts (cert PEM, key PEM, hex fingerprint), and return them.
///
/// Returns the *PEM bytes* of cert and key (string-ish) and the hex
/// fingerprint string.
fn ensure_loopback_cert(
    cert_path: &Path,
    key_path: &Path,
    fingerprint_path: &Path,
) -> Result<(String, String, String)> {
    if cert_path.exists() && key_path.exists() {
        let cert_pem = std::fs::read_to_string(cert_path)
            .with_context(|| format!("read persisted cert PEM from {}", cert_path.display()))?;
        let key_pem = std::fs::read_to_string(key_path)
            .with_context(|| format!("read persisted key PEM from {}", key_path.display()))?;
        let fingerprint = compute_cert_fingerprint(&cert_pem)?;
        // Re-persist the fingerprint file even if it already exists —
        // a missing fingerprint file would otherwise be a confusing
        // first-startup-after-corrupted-state failure mode.
        std::fs::write(fingerprint_path, &fingerprint).with_context(|| {
            format!(
                "write loopback fingerprint to {}",
                fingerprint_path.display()
            )
        })?;
        return Ok((cert_pem, key_pem, fingerprint));
    }

    // Generate fresh.
    let mut params = rcgen::CertificateParams::new(vec!["localhost".to_string()])
        .context("rcgen CertificateParams::new")?;
    let mut dn = DistinguishedName::new();
    dn.push(rcgen::DnType::CommonName, "ABERP loopback");
    params.distinguished_name = dn;
    params.key_usages = vec![
        KeyUsagePurpose::DigitalSignature,
        KeyUsagePurpose::KeyEncipherment,
    ];
    let key_pair = KeyPair::generate().context("rcgen KeyPair::generate")?;
    let cert = params
        .self_signed(&key_pair)
        .context("rcgen CertificateParams::self_signed")?;

    let cert_pem = cert.pem();
    let key_pem = key_pair.serialize_pem();
    let fingerprint = compute_cert_fingerprint(&cert_pem)?;

    std::fs::write(cert_path, &cert_pem)
        .with_context(|| format!("write loopback cert PEM to {}", cert_path.display()))?;
    std::fs::write(key_path, &key_pem)
        .with_context(|| format!("write loopback key PEM to {}", key_path.display()))?;
    std::fs::write(fingerprint_path, &fingerprint).with_context(|| {
        format!(
            "write loopback fingerprint to {}",
            fingerprint_path.display()
        )
    })?;

    // Tighten the key file's permissions on POSIX. On Windows the call
    // is a no-op; we silently skip it.
    #[cfg(unix)]
    {
        use std::os::unix::fs::PermissionsExt;
        let mut perms = std::fs::metadata(key_path)
            .with_context(|| format!("stat {}", key_path.display()))?
            .permissions();
        perms.set_mode(0o600);
        std::fs::set_permissions(key_path, perms)
            .with_context(|| format!("chmod 0600 {}", key_path.display()))?;
    }

    Ok((cert_pem, key_pem, fingerprint))
}

/// SHA-256 fingerprint of the **DER body** of the first cert in a PEM
/// bundle, hex-encoded. Matches the format `openssl x509 -fingerprint
/// -sha256 -noout -in cert.pem` produces (lower-case, no colons).
fn compute_cert_fingerprint(cert_pem: &str) -> Result<String> {
    let mut bytes = cert_pem.as_bytes();
    let cert_der = rustls_pemfile::certs(&mut bytes)
        .next()
        .ok_or_else(|| anyhow!("no certificate found in PEM bundle"))?
        .context("parse certificate PEM")?;
    let mut hasher = Sha256::new();
    hasher.update(&cert_der);
    Ok(hex::encode(hasher.finalize()))
}

/// Parse the PEM bytes into the `Vec<u8>` DER pair `axum_server`'s
/// `RustlsConfig::from_der` wants.
fn build_rustls_config(cert_pem: &str, key_pem: &str) -> Result<(Vec<Vec<u8>>, Vec<u8>)> {
    let mut cert_bytes = cert_pem.as_bytes();
    let certs: Vec<Vec<u8>> = rustls_pemfile::certs(&mut cert_bytes)
        .map(|c| c.map(|der| der.to_vec()))
        .collect::<Result<Vec<_>, _>>()
        .context("parse loopback cert PEM")?;
    if certs.is_empty() {
        return Err(anyhow!("loopback cert PEM contained no certificates"));
    }
    let mut key_bytes = key_pem.as_bytes();
    let key = rustls_pemfile::private_key(&mut key_bytes)
        .context("parse loopback key PEM")?
        .ok_or_else(|| anyhow!("loopback key PEM contained no private key"))?;
    Ok((certs, key.secret_der().to_vec()))
}

// ── Session token in the OS keychain ─────────────────────────────────

/// Look up the session token in the OS keychain for this tenant; if
/// absent, generate a fresh 256-bit random token (hex-encoded) and
/// persist it.
fn load_or_create_session_token(tenant: &str) -> Result<String> {
    let service = keychain_service_for(tenant);
    let entry = keyring::Entry::new(&service, SESSION_TOKEN_ACCOUNT)
        .context("build keyring::Entry for session token")?;
    match entry.get_password() {
        Ok(existing) if !existing.is_empty() => Ok(existing),
        Ok(_) | Err(keyring::Error::NoEntry) => {
            let fresh = generate_session_token();
            entry
                .set_password(&fresh)
                .context("write fresh session token to OS keychain")?;
            tracing::info!(
                tenant = tenant,
                "minted fresh session token in OS keychain (account `session_token`)"
            );
            Ok(fresh)
        }
        Err(e) => Err(anyhow!("keychain access for session token failed: {e}")),
    }
}

/// 32 random bytes from the OS RNG, hex-encoded. We do not pull in
/// `rand` for this — `std::time::SystemTime::now()` is the cheap
/// source for one-shot key material on a single workstation, mixed
/// with a per-process ULID. A proper rotation flow with a real RNG
/// can land when the operator-action surface needs it; for the first
/// MVP token a 256-bit value derived from system entropy is
/// sufficient.
///
/// Per CLAUDE.md rule 12, we name the trade-off loud: this is NOT a
/// cryptographic key. It is a single-workstation bearer secret that
/// gates one local HTTPS endpoint behind the OS-keychain trust
/// boundary the rest of ABERP already lives behind. A future
/// PR-9-1.5 (or session 12) can swap this for a `rand`-sourced
/// equivalent.
fn generate_session_token() -> String {
    use std::time::{SystemTime, UNIX_EPOCH};
    let now_nanos = SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .map(|d| d.as_nanos())
        .unwrap_or(0u128);
    let ulid_bytes = ulid::Ulid::new().to_bytes();
    let pid = std::process::id();
    let mut hasher = Sha256::new();
    hasher.update(now_nanos.to_le_bytes());
    hasher.update(ulid_bytes);
    hasher.update(pid.to_le_bytes());
    hex::encode(hasher.finalize())
}

// ── Axum router + handlers ───────────────────────────────────────────

/// PR-46α / session-62 — boot lifecycle discriminator on the
/// [`AppState`]. `NeedsSetup` means the keychain is empty for this
/// tenant; the listener still binds + the handshake still fires so the
/// Tauri shell + SPA can render a first-run setup wizard against the
/// loopback. `Ready` carries the operator-login string the audit-
/// ledger actor derivation needs (mirrors the pre-PR-46α
/// `Arc<String>` shape).
///
/// Single-tenant scope per the brief: the boot-state is one bit of
/// in-process state shared between the setup route (which writes when
/// transitioning) and every other route (which reads to either pull
/// the login OR reject with 503). Multi-tenant CRUD lifts this to a
/// per-tenant registry in a later PR-46β.
///
/// PR-51 / session-71 — third variant `NeedsSellerConfig` for the
/// SPA's seller-config wizard. Detected at boot when the NAV
/// credentials load but `~/.aberp/<tenant>/seller.toml` is absent or
/// missing required identity fields. The state token
/// `needs-seller-config` rides the handshake suffix so the Tauri
/// shell's first-paint dispatch picks the right wizard without an
/// extra round-trip. `operator_login` is carried on the variant
/// because NAV creds are already loaded — only the seller-config gate
/// remains; the same login feeds the audit actor once the wizard
/// flips the state to Ready.
#[derive(Debug, Clone)]
pub enum ServeBootState {
    /// Keychain has no NAV credentials for this tenant. The only
    /// route that responds to mutations is
    /// `POST /api/setup-nav-credentials`; every other gated route
    /// returns 503 with a typed body the SPA renders inline.
    NeedsSetup,
    /// PR-51 / session-71 — keychain populated, but
    /// `~/.aberp/<tenant>/seller.toml` is missing or its identity
    /// block (legal_name + tax_number + address) is incomplete. The
    /// SPA's `SellerConfigWizard` fires; `POST /api/setup-seller-info`
    /// is the only mutation route that responds (bypasses Bearer-auth
    /// for the same A170 chicken-and-egg reason as the NAV-creds
    /// wizard). Every other gated route returns 503.
    NeedsSellerConfig { operator_login: String },
    /// Keychain is populated; the per-request audit-actor login was
    /// extracted at startup (or at setup-route-transition time) and
    /// is cached here for the Actor derivation site.
    Ready { operator_login: String },
}

impl ServeBootState {
    /// String token emitted on the handshake `state=<token>` suffix
    /// (PR-46α). The Tauri shell's `handshake::parse` reads it to
    /// route the SPA's first paint between the normal app and the
    /// setup wizard.
    ///
    /// PR-51 / session-71 — added the `needs-seller-config` token for
    /// the new boot-state variant. Mirror in
    /// `apps/aberp-ui/src/handshake.rs::parse_state_value`.
    pub fn state_token(&self) -> &'static str {
        match self {
            ServeBootState::NeedsSetup => "needs-setup",
            ServeBootState::NeedsSellerConfig { .. } => "needs-seller-config",
            ServeBootState::Ready { .. } => "ready",
        }
    }

    /// `true` iff the backend is past the needs-setup gate. Used by
    /// the route precondition helper.
    pub fn is_ready(&self) -> bool {
        matches!(self, ServeBootState::Ready { .. })
    }

    /// PR-51 / session-71 — `true` iff a setup-flow route (NAV creds
    /// OR seller info) should bypass the Bearer-auth gate. The
    /// chicken-and-egg posture from A170 (the SPA wizard runs BEFORE
    /// the operator has acquired a session token) extends to the
    /// seller-config wizard too. Used by both setup-route handlers.
    pub fn allows_setup_bypass(&self) -> bool {
        !matches!(self, ServeBootState::Ready { .. })
    }
}

/// PR-51 / session-71 — pick the boot state to enter when NAV creds
/// load cleanly. Reads `~/.aberp/<tenant>/seller.toml` and:
///
///   - missing file OR identity-incomplete → `NeedsSellerConfig`
///   - identity present → `Ready`
///
/// Reads outside the `RwLock` so a slow filesystem doesn't delay the
/// listener bind; called once at boot. Errors reading the file fall
/// through to `NeedsSellerConfig` with a tracing warning — that
/// surfaces the bad file to the operator AND lets the wizard
/// overwrite it (better than refusing to boot).
fn derive_initial_boot_state_with_seller_check(
    operator_login: String,
    tenant: &str,
) -> ServeBootState {
    match setup_seller_info::seller_toml_path_for_tenant(tenant) {
        Ok(path) => match setup_seller_info::read_seller_identity(&path) {
            Ok(Some(_id)) => {
                tracing::info!(
                    seller_toml = %path.display(),
                    "seller.toml identity block present; entering Ready boot state"
                );
                ServeBootState::Ready { operator_login }
            }
            Ok(None) => {
                tracing::warn!(
                    seller_toml = %path.display(),
                    "seller.toml missing or identity-incomplete; entering needs-seller-config boot state; \
                     SPA SellerConfigWizard will populate via POST /api/setup-seller-info"
                );
                ServeBootState::NeedsSellerConfig { operator_login }
            }
            Err(e) => {
                tracing::warn!(
                    seller_toml = %path.display(),
                    error = %format!("{e:#}"),
                    "seller.toml read failed; entering needs-seller-config boot state so the wizard can overwrite"
                );
                ServeBootState::NeedsSellerConfig { operator_login }
            }
        },
        Err(e) => {
            tracing::warn!(
                error = %format!("{e:#}"),
                "HOME env var missing; entering needs-seller-config boot state so the wizard can surface the error"
            );
            ServeBootState::NeedsSellerConfig { operator_login }
        }
    }
}

/// Per-request shared state passed to every authenticated handler.
///
/// Public surface as of PR-44ε.UI / session-58 so the
/// `apps/aberp/tests/serve_pdf_route.rs` integration test can
/// exercise [`get_invoice_pdf`] directly without spinning the axum
/// listener (the listener still owns the lifecycle in `run`). Fields
/// stay narrow — the cert + fingerprint + tokio runtime stay private
/// to `run` per ADR-0007 §Transport (the SPA never sees them, and
/// neither does the read-path test surface).
///
/// PR-44ζ / session-59 added `operator_login` so the new
/// `POST /invoices/issue` mutation route can derive an `Actor` per
/// request without re-loading NAV credentials from the keychain
/// (which already happened once at `run` startup). The full
/// [`NavCredentials`] is NOT stored on the state — only the
/// non-secret `login()` value, which is the only field the audit-
/// ledger actor needs. Keeps secrets out of the route surface.
///
/// PR-46α / session-62 — `operator_login` moved inside the
/// [`ServeBootState`] enum (`Arc<RwLock<ServeBootState>>`). On a
/// fresh install with empty keychain the backend now starts in
/// `NeedsSetup`; the new `POST /api/setup-nav-credentials` route
/// flips it to `Ready` after writing the four keychain entries.
/// Every existing route checks the state via [`require_ready`] and
/// either pulls `operator_login` OR returns 503 needs-setup.
#[derive(Clone)]
pub struct AppState {
    pub db_path: Arc<PathBuf>,
    pub tenant: TenantId,
    /// PR-45a / session-61 — handle to the background-computed binary
    /// hash. Reading a debug `aberp` binary off cold disk + hashing it
    /// took ~7.5s in `aberp serve`'s synchronous boot path, which
    /// blew the desktop shell's 10s `HANDSHAKE_TIMEOUT`. The compute
    /// now runs on a dedicated OS thread spawned at `run` entry; HTTP
    /// handlers call `binary_hash.wait()` (essentially zero-latency
    /// after a few seconds of uptime). See [`BinaryHashHandle`] for
    /// the failure-mode posture.
    pub binary_hash: BinaryHashHandle,
    pub session_token: Arc<String>,
    /// PR-46α / session-62 — boot lifecycle gate. `Ready` carries
    /// the operator-login string; `NeedsSetup` means the keychain is
    /// empty and only the setup route responds to mutations.
    pub boot_state: Arc<std::sync::RwLock<ServeBootState>>,
    /// Session-149 — in-process secrets cache populated during the boot
    /// keychain-read burst. The SMTP password is read ONCE at boot and
    /// served from here for every post-boot consumer (Settings GET/PUT,
    /// email send, test connection), so the OS keychain is never read
    /// lazily mid-session. See [`SecretsCache`].
    pub secrets_cache: SecretsCache,
    /// Session-161 — concurrency cap for the indefinite NAV poll
    /// daemons. Each [`poll_ack::run_nav_poll_daemon`] holds one permit
    /// for its whole lifetime, so this bounds the number of invoices
    /// being actively watched (post-issue spawns + app-boot recovery
    /// spawns combined). At [`NAV_POLL_DAEMON_CONCURRENCY`] permits the
    /// steady-state poll rate is ≤ that many polls/min — well inside
    /// NAV's published limits. Excess spawns block on `acquire()` until
    /// a daemon terminates and frees its slot.
    pub nav_poll_semaphore: Arc<tokio::sync::Semaphore>,
    /// PR-209 / S213 — the graceful-shutdown coordinator's token,
    /// cloned into every dynamically-spawned NAV poll daemon (post-
    /// issue auto-poll + chain post-issue tail). Boot-time daemons
    /// (boot-recovery / AP sync / quote-intake) receive the token
    /// directly from the coordinator in `run`; the post-issue path
    /// has no other handle on the coordinator, so the token rides on
    /// `AppState` to reach those spawn sites.
    pub shutdown_token: tokio_util::sync::CancellationToken,
    /// S240 / PR-234 — shared handle to the MES adapter registry.
    /// Created empty at boot, populated by `mes_boot::boot_mes_adapters`
    /// after each adapter's `start()` succeeds. The Workshop dashboard
    /// handler takes a read lock to call `health_snapshot()`, replacing
    /// the prior `snapshot_mes_adapter_config()` env-var read with a
    /// live registry probe per [[trust-code-not-operator]].
    pub adapter_registry: Arc<std::sync::RwLock<AdapterRegistry>>,
}

/// Session-161 — max number of NAV poll daemons polling concurrently.
/// At the 1-minute phase-2 cadence this caps total NAV poll traffic at
/// ≤ 50 requests/min even with every slot saturated.
pub const NAV_POLL_DAEMON_CONCURRENCY: usize = 50;

fn build_router(state: AppState) -> Router {
    Router::new()
        .route("/health", get(handle_health))
        // S166 / prod-prep PR #2 — the operator's one-time consent to
        // real fiscal operation. A `/health` subroute (read by the SPA's
        // first-launch modal) that, unusually, writes to the audit
        // ledger: the human acknowledgment is a legal-grade event.
        .route(
            "/health/acknowledge-first-prod-launch",
            post(handle_acknowledge_first_prod_launch),
        )
        .route("/invoices", get(handle_list_invoices))
        .route("/invoices/issue", post(handle_issue_invoice))
        .route("/invoices/:id", get(handle_get_invoice))
        .route("/invoices/:id/pdf", get(handle_get_invoice_pdf))
        .route("/invoices/:id/submit", post(handle_submit_invoice))
        .route("/invoices/:id/poll-ack", post(handle_poll_ack))
        .route("/api/invoices/:id/storno", post(handle_storno_invoice))
        .route(
            "/api/invoices/:id/modification",
            post(handle_modification_invoice),
        )
        .route(
            "/api/invoices/:id/issuance-input",
            get(handle_get_issuance_input),
        )
        // PR-70 / ADR-0039 — operational "quick mark as paid" route.
        // Records a payment receipt against a Finalized invoice
        // WITHOUT changing the NAV regulatory state ladder
        // (paid-vs-unpaid is operational metadata, queried separately).
        .route(
            "/api/invoices/:id/mark-paid",
            post(handle_mark_invoice_paid),
        )
        // PR-217 / S220 — operator-paced manual partner link on a
        // restored ExtNav row. Per [[aberp-extnav-partner-nav-gap]] NAV
        // does not expose buyer info for invoices submitted via other
        // software, so [`restore_outgoing::run_buyer_backfill_once`] is
        // structurally unable to populate `customer_name` for those
        // rows. The SPA exposes a partner-picker for these so the
        // operator can annotate from their own records.
        .route(
            "/api/restored-invoices/:id/partner",
            post(handle_set_restored_partner),
        )
        .route("/audit/:invoice_id", get(handle_get_audit))
        // PR-46α / session-62 — first-run setup route. Accepts the
        // four NAV credential artifacts and writes them to the OS
        // keychain. In `NeedsSetup` mode it bypasses bearer-auth (the
        // SPA wizard has no other way to populate the keychain on a
        // fresh machine — A170); once the boot state transitions to
        // `Ready` the route requires the standard Bearer-auth header
        // like every other mutation.
        .route(
            "/api/setup-nav-credentials",
            post(handle_setup_nav_credentials),
        )
        // PR-51 / session-71 — second-run-setup route. Accepts the
        // operator-typed seller identity (legal name + tax number +
        // address) + bank info and writes it to
        // `~/.aberp/<tenant>/seller.toml` atomically. In
        // `NeedsSetup` OR `NeedsSellerConfig` mode the route
        // bypasses Bearer-auth (the SPA wizard chain has no session-
        // token bearer yet — same A170 chicken-and-egg posture as
        // the NAV-creds wizard); once the boot state transitions to
        // `Ready` the route requires the standard Bearer-auth
        // header (so an operator can re-run the wizard from the
        // settings screen without losing auth).
        .route("/api/setup-seller-info", post(handle_setup_seller_info))
        // PR-53 / session-73 — read-side counterparts of the two setup
        // routes, plus the single-slot rotate route. All three are
        // Ready-only + bearer-required (rotation happens after the
        // wizard chain — A170 only applies to first-run-setup).
        .route("/api/seller-info", get(handle_get_seller_info))
        .route(
            "/api/nav-credentials-status",
            get(handle_get_nav_credentials_status),
        )
        .route(
            "/api/rotate-nav-credential",
            post(handle_rotate_nav_credential),
        )
        // PR-48α / session-68 — partner CRUD. Five routes (list +
        // create on the collection; get + update + delete on the
        // resource), all require_ready + bearer auth — partners is a
        // Ready-state feature, not a first-run-setup surface.
        .route(
            "/api/partners",
            get(handle_list_partners).post(handle_create_partner),
        )
        .route(
            "/api/partners/:id",
            get(handle_get_partner)
                .put(handle_update_partner)
                .delete(handle_delete_partner),
        )
        // PR-172 — buyer-facing notes typeahead source. GET-only,
        // ready+bearer-gated. `?scope=line|invoice|storno` is required.
        // Returns the most-recent-first deduplicated list of operator-
        // typed notes for the requested scope. Empty array on a fresh
        // tenant (no audit history yet).
        .route("/api/notes-history", get(handle_get_notes_history))
        // PR-91 — products master-data CRUD. Five routes (list + create
        // on the collection; get + update + delete on the resource), all
        // require_ready + bearer auth — products is a Ready-state
        // feature, not a first-run-setup surface. Mirrors the partners
        // route shape.
        .route(
            "/api/products",
            get(handle_list_products).post(handle_create_product),
        )
        .route(
            "/api/products/:id",
            get(handle_get_product)
                .put(handle_update_product)
                .delete(handle_delete_product),
        )
        // S231 / PR-227 / ADR-0061 — Stage 3 Phase γ Inventory v1.
        // GET lists the per-product `stock_movements` ledger
        // (descending by at_iso8601, paginated). POST appends one
        // operator-typed manual adjustment movement (reason +
        // qty_delta + optional notes). Both require_ready + bearer
        // auth; POST DoS-bounded by an explicit Json size cap +
        // closed-vocab reason validation per [[trust-code-not-operator]].
        // The dashboard's low-stock click-through reads
        // `GET /api/products/low-stock` (separate route below).
        .route(
            "/api/products/:id/stock-movements",
            get(handle_list_stock_movements).post(handle_create_stock_movement),
        )
        .route(
            "/api/products/low-stock",
            get(handle_list_low_stock_products),
        )
        // S232 / PR-228 / ADR-0062 — Stage 3 Phase γ Work Orders v1.
        // GET lists tenant WOs (optional `?state=` filter +
        // pagination); POST creates a new WO with product_id +
        // qty_target + routing-op rows. The detail GET expands the
        // routing operations + active BOM snapshot. The transitions
        // POST is the SAME handler future adapter events call per
        // ADR-0062 §3 — actor captured into the audit entry only.
        // BOM author GET / POST under `/api/products/:id/bom`.
        // All require_ready + bearer auth. DoS bounds per
        // [[trust-code-not-operator]]: axum's default Json size cap +
        // explicit per-WO routing-op cap (200) + per-BOM line cap
        // (200) inside the repository.
        .route(
            "/api/work-orders",
            get(handle_list_work_orders).post(handle_create_work_order),
        )
        .route("/api/work-orders/:id", get(handle_get_work_order_detail))
        .route(
            "/api/work-orders/:id/transitions",
            post(handle_transition_work_order),
        )
        // S233 / PR-229 Part A — per-routing-op Complete button (the
        // Active op only; cascade advances the next op + auto-creates
        // a Pending QA inspection).
        .route(
            "/api/work-orders/:id/routing-ops/:op_id/transitions",
            post(handle_transition_routing_op),
        )
        .route(
            "/api/products/:id/bom",
            get(handle_get_product_bom).post(handle_put_product_bom),
        )
        // S233 / PR-229 / ADR-0063 — Stage 3 Phase γ QA queue v1.
        // GET lists tenant QA inspections (optional `?state=` filter +
        // pagination — defaults to all states); detail GET; decisions
        // POST is the SAME handler future adapter events call per
        // ADR-0063 §3.
        .route("/api/qa-inspections", get(handle_list_qa_inspections))
        .route("/api/qa-inspections/:id", get(handle_get_qa_inspection))
        .route(
            "/api/qa-inspections/:id/decisions",
            post(handle_decide_qa_inspection),
        )
        // S234 / PR-230 / ADR-0064 — Stage 3 Phase γ Dispatch board v1.
        // GET lists tenant dispatches (optional `?state=` filter +
        // pagination — defaults to all states); detail GET; eligible-WO
        // read for the SPA's "Ready to dispatch" panel; create POST
        // refuses ineligible WO + duplicate-for-WO loud per ADR-0064 §2;
        // mark-shipped POST is the atomic transition (stock movement +
        // injected invoice spawn + audit) per ADR-0064 §4 + §5; cancel
        // POST is valid only from Drafted.
        .route(
            "/api/dispatches",
            get(handle_list_dispatches).post(handle_create_dispatch),
        )
        .route(
            "/api/dispatches/eligible-work-orders",
            get(handle_list_eligible_work_orders),
        )
        .route("/api/dispatches/:id", get(handle_get_dispatch))
        .route(
            "/api/dispatches/:id/ship",
            post(handle_mark_dispatch_shipped),
        )
        .route("/api/dispatches/:id/cancel", post(handle_cancel_dispatch))
        // S236 / PR-230b — pre-allocation invoice-draft routes. The
        // BillingInvoiceSpawner creates rows here on dispatches→Shipped;
        // these routes let the SPA list, inspect, and delete drafts.
        // Promotion to a Ready invoice rides the existing IssueInvoice
        // form path (the SPA pre-fills the form from a GET to
        // /api/invoice-drafts/:id, then DELETEs the draft after the
        // invoice creation succeeds; cross-pipeline atomic promote is
        // deferred to a future PR per the PR-230b scope-reduction).
        .route("/api/invoice-drafts", get(handle_list_invoice_drafts))
        .route(
            "/api/invoice-drafts/:id",
            get(handle_get_invoice_draft).delete(handle_delete_invoice_draft),
        )
        // S177 / PR-177 — AP module v1 BACKEND. Incoming-invoice list +
        // detail + manual ingestion + three closed-vocab status
        // transitions. All require_ready + bearer auth. The NAV
        // auto-sync daemon (queryInvoiceDigest INBOUND fanout) is a
        // SEPARATE PR — these routes are the foundation S178's UI
        // consumes and the same entry points the future daemon will
        // call. See `incoming_invoices.rs` module docs.
        .route("/api/incoming-invoices", get(handle_list_incoming_invoices))
        .route(
            "/api/incoming-invoices/ingest",
            post(handle_ingest_incoming_invoice),
        )
        .route(
            "/api/incoming-invoices/:id",
            get(handle_get_incoming_invoice),
        )
        .route(
            "/api/incoming-invoices/:id/mark-paid",
            post(handle_mark_incoming_paid),
        )
        .route(
            "/api/incoming-invoices/:id/mark-outstanding",
            post(handle_mark_incoming_outstanding),
        )
        .route(
            "/api/incoming-invoices/:id/mark-irrelevant",
            post(handle_mark_incoming_irrelevant),
        )
        // S178 / PR-178 — operator-clicked manual AP sync trigger.
        // Synchronous (blocks the response until the cycle returns
        // counts). Same daemon code path as the cadence tick;
        // emits one `IncomingInvoiceSyncCycleCompleted` audit
        // entry with `trigger="manual"`.
        .route(
            "/api/incoming-invoices/sync-now",
            post(handle_sync_incoming_now),
        )
        // S197 / PR-197 — XML download for an AP-side row whose S197
        // `queryInvoiceData` follow-on fetch has populated
        // `nav_xml_path`. Returns the on-disk InvoiceData XML bytes
        // verbatim with `Content-Type: application/xml` + a
        // `Content-Disposition: attachment` filename built from
        // supplier + invoice number. 404 when the row is missing OR
        // when `nav_xml_path` is still NULL (the digest-only fallback;
        // operator sees a disabled button in the SPA, so this route
        // 404 is defence-in-depth against direct curl calls).
        .route(
            "/api/incoming-invoices/:id/xml",
            get(handle_get_incoming_invoice_xml),
        )
        // S180 / PR-180 — NAV-as-DR restore wizard. POST { year }
        // walks NAV's `queryInvoiceDigest OUTBOUND` view for that
        // year and mirrors each new digest into the local
        // `restored_invoice` table. Operator-triggered; require_ready
        // + bearer auth; synchronous (12 months × pagination, may
        // take several seconds on a populated tenant). GET lists
        // every restored row for the tenant — used by the wizard
        // to render the "already-restored" panel.
        .route(
            "/api/restore-from-nav-outgoing",
            post(handle_restore_from_nav_outgoing),
        )
        .route("/api/restored-invoices", get(handle_list_restored_invoices))
        // S225 / PR-221 — financial-statistics dashboard endpoint.
        // Read-only aggregation over invoice + restored_invoice +
        // ap_invoice (digest-only sources combined with audit-ledger-
        // derived state). Query params: `period` (default current
        // month), `date_basis` (default `teljesites`). No audit-ledger
        // writes — reports are pure views per the no-silent-write
        // posture (CLAUDE.md rule 12).
        .route("/api/reports/financial", get(handle_financial_report))
        // S235 / PR-231 — Workshop / Műhely operator dashboard. ONE
        // endpoint that returns every count tile in one bundle: WO by
        // state, low-stock count, QA by state, dispatch by state +
        // eligible + shipped-today, today's invoice headline,
        // recent-activity tail, MES adapter env snapshot. The SPA
        // wall-TV polls this every 10s; one DuckDB tx beats six round-
        // trips. No writes — pure aggregation; same no-silent-write
        // posture as the financial-statistics route.
        .route("/api/workshop/dashboard", get(handle_workshop_dashboard))
        // PR-72 / session-94 — multi-bank-account CRUD (PR-B of the
        // multi-bank initiative; ADR-0040 §addendum). Five routes
        // (list + create on the collection; update + delete + flip-
        // default on the resource), all require_ready + bearer auth —
        // bank-accounts is a Ready-state feature; first-run setup goes
        // through SellerConfigWizard. The set-default flip is its own
        // route to keep the mental model crisp (mutating the default
        // is a separate intent from editing the entry's fields).
        .route(
            "/api/seller/banks",
            get(handle_list_seller_banks).post(handle_create_seller_bank),
        )
        .route(
            "/api/seller/banks/:id",
            axum::routing::put(handle_update_seller_bank).delete(handle_delete_seller_bank),
        )
        .route(
            "/api/seller/banks/:id/set-default",
            post(handle_set_default_seller_bank),
        )
        // PR-89 — operator-configurable invoice-number template
        // (`[seller.numbering]` section of seller.toml). GET returns
        // the persisted template (or the default INV-default/00001
        // shape when absent); PUT replaces it atomically, preserving
        // every other section of seller.toml (identity + banks).
        .route(
            "/api/seller/numbering",
            get(handle_get_seller_numbering).put(handle_put_seller_numbering),
        )
        // PR-92 / ADR-0047 — SMTP email delivery surfaces. GET returns
        // the `[seller.smtp]` config (non-secrets only) + a `password_set`
        // probe of the keychain. PUT writes the config (merge-not-replace
        // on seller.toml + optional password rotation to keychain).
        // POST /api/invoices/:id/email is the operator-clicked manual
        // send button on InvoiceDetail. All three require_ready + bearer
        // auth.
        .route(
            "/api/smtp-config",
            get(handle_get_smtp_config).put(handle_put_smtp_config),
        )
        // PR-98 — operator-clicked "Test connection" button on the
        // TenantSettings SMTP subsection. Runs the TLS handshake +
        // AUTH + NOOP using the operator-typed config + (entered
        // password OR existing keychain entry); reports the typed
        // outcome WITHOUT sending mail and WITHOUT persisting
        // anything.
        .route("/api/seller/smtp/test", post(handle_test_smtp_connection))
        .route(
            "/api/invoices/:id/email",
            post(handle_email_invoice_to_buyer),
        )
        // S211 / PR-210 — quote-intake daemon config + queue surface.
        // GET returns the persisted `[quote_intake]` config + a
        // `has_token` keychain probe + the latest poll summary; PUT
        // writes the toml section (merge-not-replace) + optional
        // token rotation to the keychain; POST /test runs a
        // read-only `GET /api/quotes?status=approved` against the
        // configured URL with the stored token (no persistence,
        // remote-read-only); GET /quotes returns staged
        // `quote_intake_log` rows for the operator queue.
        .route(
            "/api/quote-intake/config",
            get(handle_get_quote_intake_config).put(handle_put_quote_intake_config),
        )
        .route(
            "/api/quote-intake/test",
            post(handle_test_quote_intake_connection),
        )
        .route("/api/quote-intake/quotes", get(handle_list_quote_intake))
        .with_state(state)
}

/// PR-46α / session-62 — typed response body emitted when the backend
/// is in `NeedsSetup` and a gated route is called. The SPA reads the
/// `state` field to dispatch to the first-run wizard; the human-
/// readable `message` is rendered inline so an operator inspecting
/// the route via `curl` sees a recognisable string.
fn needs_setup_response() -> Response {
    (
        StatusCode::SERVICE_UNAVAILABLE,
        Json(serde_json::json!({
            "state": "needs-setup",
            "message": "Set up NAV credentials before using this endpoint.",
        })),
    )
        .into_response()
}

/// PR-51 / session-71 — sibling of [`needs_setup_response`] for the
/// post-NAV-creds, pre-seller-config gate. SPA reads `state` to
/// dispatch to `SellerConfigWizard` instead of `SetupWizard`.
fn needs_seller_config_response() -> Response {
    (
        StatusCode::SERVICE_UNAVAILABLE,
        Json(serde_json::json!({
            "state": "needs-seller-config",
            "message": "Save seller identity (legal name, tax number, address) before using this endpoint.",
        })),
    )
        .into_response()
}

/// PR-46α / session-62 — precondition gate for every Ready-only
/// route. Returns `Ok(operator_login)` if the backend is `Ready`;
/// returns `Err(response)` with the typed 503 needs-setup body
/// otherwise. The poison-arm guards against a panic in the setup
/// route's write transaction leaving the RwLock unusable — that's
/// treated as a 500 (the operator-visible message points at
/// internal-state corruption, which is the truth at that point).
///
/// PR-51 / session-71 — `NeedsSellerConfig` now exists as a third
/// state; the gate emits a distinct 503 body (`needs-seller-config`)
/// so the SPA can route the operator to the right wizard.
fn require_ready(state: &AppState) -> std::result::Result<String, Response> {
    let guard = state.boot_state.read().map_err(|e| {
        tracing::error!(error = %e, "boot_state RwLock poisoned");
        (
            StatusCode::INTERNAL_SERVER_ERROR,
            Json(error_body("boot_state lock poisoned".to_string())),
        )
            .into_response()
    })?;
    match &*guard {
        ServeBootState::Ready { operator_login } => Ok(operator_login.clone()),
        ServeBootState::NeedsSetup => Err(needs_setup_response()),
        ServeBootState::NeedsSellerConfig { .. } => Err(needs_seller_config_response()),
    }
}

/// PR-46α / session-62 — request body for
/// `POST /api/setup-nav-credentials`. Field names are the
/// operator-readable form rather than the on-disk `ITEM_*` keychain
/// names; the SPA composer mirrors this shape.
#[derive(Debug, Deserialize)]
pub struct SetupNavCredentialsRequest {
    pub technical_user_login: String,
    pub technical_user_password: String,
    pub xml_sign_key: String,
    pub xml_change_key: String,
}

/// PR-46α / session-62 — response body for the setup route. Surfaces
/// the post-write boot state so the SPA can flip its wizard view-mode
/// to the normal app without a second probe roundtrip.
///
/// PR-51 / session-71 — `state` widened from a single `"ready"`
/// literal to either `"ready"` or `"needs-seller-config"`. The
/// chained-wizard posture (NAV creds first → seller config next when
/// the file is missing) means the post-success state is no longer
/// always Ready. The SPA's Tauri-shell wrapper reads this field and
/// flips its boot-state mirror to the matching variant.
#[derive(Debug, Serialize)]
struct SetupNavCredentialsResponse {
    state: &'static str,
}

/// PR-46α / session-62 — `POST /api/setup-nav-credentials` handler.
///
/// 1. Bearer-auth check ONLY if already `Ready` (chicken-and-egg
///    bypass in `NeedsSetup`; A170).
/// 2. Validate-then-write via [`setup_nav_credentials::setup_credentials_from_inputs`]
///    (the shared core both the CLI subcommand and this route go
///    through — A167).
/// 3. Re-load NAV credentials from the now-populated keychain to
///    extract the audit-actor login.
/// 4. Take the boot_state write lock and flip
///    `NeedsSetup → Ready { operator_login }`.
/// 5. Return 200 with `{ "state": "ready" }`. From the SPA's
///    perspective, this is the operator's exit from the wizard.
///
/// Failure modes:
///   - `400 Bad Request` — validation failure (empty field).
///   - `401 Unauthorized` — bearer missing in `Ready` mode.
///   - `500 Internal Server Error` — keychain write failed OR the
///     re-load couldn't find the entries we just wrote (which would
///     indicate the OS keychain backend silently dropped a write —
///     CLAUDE.md rule 12 surfaces it as a 500 rather than a partial-
///     success lie).
async fn handle_setup_nav_credentials(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<SetupNavCredentialsRequest>,
) -> Response {
    // Bearer check only in Ready mode. In NeedsSetup mode the operator
    // has no way to acquire a bearer (the SPA's session-token loader
    // path runs after the backend handshake, but the setup wizard
    // fires BEFORE the normal app mounts — A170).
    let is_ready_pre_call = state
        .boot_state
        .read()
        .map(|g| g.is_ready())
        .unwrap_or(false);
    if is_ready_pre_call {
        if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
            return resp;
        }
    }

    let inputs = NavCredentialInputs {
        technical_user_login: request.technical_user_login,
        technical_user_password: request.technical_user_password,
        xml_sign_key: request.xml_sign_key,
        xml_change_key: request.xml_change_key,
    };

    match setup_nav_credentials_request(&state, &inputs) {
        Ok(next_state_token) => Json(SetupNavCredentialsResponse {
            state: next_state_token,
        })
        .into_response(),
        Err(SetupRouteHelperError::Validation(msg)) => {
            (StatusCode::BAD_REQUEST, Json(error_body(msg))).into_response()
        }
        Err(SetupRouteHelperError::Other(e)) => internal_error("setup_nav_credentials_request", e),
    }
}

/// PR-46α / session-62 — typed error from
/// [`setup_nav_credentials_request`]. The route handler maps
/// `Validation` → 400 and `Other` → 500 via the existing
/// [`internal_error`] helper.
#[derive(Debug)]
pub enum SetupRouteHelperError {
    Validation(String),
    Other(anyhow::Error),
}

impl From<anyhow::Error> for SetupRouteHelperError {
    fn from(e: anyhow::Error) -> Self {
        SetupRouteHelperError::Other(e)
    }
}

/// PR-46α / session-62 — library helper that backs the
/// `POST /api/setup-nav-credentials` handler. Extracted as `pub` so
/// the integration test can hit it for end-to-end pin tests without
/// spinning the HTTPS listener (same posture as `get_invoice_pdf` per
/// A158 and `issue_invoice_request` per A159 / A162 / A163).
///
/// On success: writes the four keychain entries via the shared core,
/// re-loads to extract the operator login, and flips the boot state
/// to Ready (or `NeedsSellerConfig` if the seller.toml is still
/// missing — PR-51 / session-71 chained-wizard posture). On
/// validation failure: returns `SetupRouteHelperError::Validation`
/// (→ 400). On any other error: returns
/// `SetupRouteHelperError::Other` (→ 500).
///
/// Returns the `state_token` of the post-transition boot state
/// (`"ready"` or `"needs-seller-config"`) so the HTTP route layer can
/// echo it on the 200 response body — the SPA's Tauri-shell wrapper
/// reads it to flip its mirror to the right variant without a second
/// probe.
pub fn setup_nav_credentials_request(
    state: &AppState,
    inputs: &NavCredentialInputs,
) -> std::result::Result<&'static str, SetupRouteHelperError> {
    match setup_nav_credentials::setup_credentials_from_inputs(state.tenant.as_str(), inputs) {
        Ok(()) => {}
        Err(SetupCredentialsError::Validation(msg)) => {
            return Err(SetupRouteHelperError::Validation(msg));
        }
        Err(SetupCredentialsError::Backend(e)) => {
            return Err(SetupRouteHelperError::Other(e));
        }
    }

    // Re-load to confirm the writes landed AND to extract the actor
    // login. A re-load failure here would indicate the OS keychain
    // silently dropped one of the four writes — loud per rule 12.
    let operator_login = NavCredentials::load_from_keychain(state.tenant.as_str())
        .map_err(|e| {
            SetupRouteHelperError::Other(anyhow!(e).context(
                "setup route wrote keychain entries but re-load failed; \
                 keychain backend may have silently dropped a write",
            ))
        })?
        .login()
        .to_string();

    // Flip the boot state. The write-lock acquisition can only fail
    // on a poisoned RwLock — same surface as `require_ready`'s poison
    // arm.
    //
    // PR-51 / session-71 — the post-NAV-creds transition is no longer
    // unconditionally Ready. If the per-tenant seller.toml is still
    // missing the wizard chain continues with the seller-config step;
    // the SPA's next `getBootStatus` poll picks up
    // `needs-seller-config` and dispatches `SellerConfigWizard`.
    let next_state =
        derive_initial_boot_state_with_seller_check(operator_login, state.tenant.as_str());
    let next_token = next_state.state_token();
    let mut guard = state.boot_state.write().map_err(|e| {
        SetupRouteHelperError::Other(anyhow!(
            "boot_state RwLock poisoned during setup transition: {e}"
        ))
    })?;
    *guard = next_state;

    tracing::info!(
        tenant = %state.tenant.as_str(),
        next_state = next_token,
        "NAV credentials populated via setup route; boot state transitioned"
    );

    Ok(next_token)
}

// ── PR-51 / session-71 — POST /api/setup-seller-info ─────────────────

/// PR-51 / session-71 — request body for
/// `POST /api/setup-seller-info`. Mirror of the SPA composer
/// `seller-config.ts::composeSellerConfigBody`. Snake_case wire
/// names; address + bank are flat sub-objects so the SPA's form
/// state maps 1:1 to the wire shape with no per-field renaming.
#[derive(Debug, Deserialize)]
pub struct SetupSellerInfoRequest {
    pub legal_name: String,
    pub tax_number: String,
    #[serde(default)]
    pub eu_vat_number: Option<String>,
    pub address: SetupSellerInfoAddress,
    #[serde(default)]
    pub bank: Option<SetupSellerInfoBank>,
}

#[derive(Debug, Deserialize)]
pub struct SetupSellerInfoAddress {
    pub country_code: String,
    pub postal_code: String,
    pub city: String,
    pub street: String,
}

#[derive(Debug, Deserialize, Default)]
pub struct SetupSellerInfoBank {
    #[serde(default)]
    pub account_number: Option<String>,
    #[serde(default)]
    pub iban: Option<String>,
    #[serde(default)]
    pub name: Option<String>,
    #[serde(default)]
    pub swift_bic: Option<String>,
}

/// PR-51 / session-71 — response body for the seller-info setup
/// route. `state` is always `"ready"` (a successful write means the
/// last gate has passed); the explicit field keeps the SPA's wrapper
/// posture identical to the NAV-creds route's response (one field
/// the Tauri shell reads to flip its mirror).
#[derive(Debug, Serialize)]
struct SetupSellerInfoResponse {
    state: &'static str,
}

/// PR-51 / session-71 — typed 400 body for field-level validation
/// failures. Mirrors the shape the SPA's `seller-config.ts` parser
/// reads: a top-level `error` discriminant + a `fields` array of
/// `{field, message}` records the wizard renders inline next to the
/// offending input.
#[derive(Serialize)]
struct SetupSellerInfoErrorBody {
    error: &'static str,
    fields: Vec<SetupSellerInfoFieldError>,
}

#[derive(Serialize)]
struct SetupSellerInfoFieldError {
    field: &'static str,
    message: String,
}

const ERR_SELLER_INFO_VALIDATION: &str = "validation_failed";

/// PR-51 / session-71 — `POST /api/setup-seller-info` handler. Same
/// shape as `handle_setup_nav_credentials`:
///
///   1. Bearer-auth check ONLY when already `Ready` (A170 bypass
///      while a wizard chain is in flight).
///   2. Validate-then-write via
///      [`setup_seller_info::setup_seller_info_from_inputs`] (the
///      shared core).
///   3. Take the boot_state write lock and flip to `Ready` (this is
///      the last gate; success means the operator is done).
///   4. Return 200 with `{ "state": "ready" }`.
///
/// Failure modes:
///   - `400 Bad Request` — one or more fields failed validation; the
///     typed body carries the per-field errors.
///   - `401 Unauthorized` — bearer missing in `Ready` mode.
///   - `500 Internal Server Error` — atomic write failed (parent
///     mkdir, tempfile open / write / fsync / rename, chmod).
async fn handle_setup_seller_info(
    headers: HeaderMap,
    State(state): State<AppState>,
    Json(request): Json<SetupSellerInfoRequest>,
) -> Response {
    let bypass_bearer = state
        .boot_state
        .read()
        .map(|g| g.allows_setup_bypass())
        .unwrap_or(false);
    if !bypass_bearer {
        if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
            return resp;
        }
    }

    let bank = request.bank.unwrap_or_default();
    let inputs = SellerInfoInputs {
        legal_name: request.legal_name,
        tax_number: request.tax_number,
        eu_vat_number: request.eu_vat_number,
        address_country_code: request.address.country_code,
        address_postal_code: request.address.postal_code,
        address_city: request.address.city,
        address_street: request.address.street,
        bank_account_number: bank.account_number,
        iban: bank.iban,
        bank_name: bank.name,
        swift_bic: bank.swift_bic,
    };

    match setup_seller_info_request(&state, &inputs, None) {
        Ok(()) => Json(SetupSellerInfoResponse { state: "ready" }).into_response(),
        Err(SetupSellerRouteError::Validation(fields)) => {
            let body = SetupSellerInfoErrorBody {
                error: ERR_SELLER_INFO_VALIDATION,
                fields: fields
                    .into_iter()
                    .map(|f| SetupSellerInfoFieldError {
                        field: f.field,
                        message: f.message,
                    })
                    .collect(),
            };
            (StatusCode::BAD_REQUEST, Json(body)).into_response()
        }
        Err(SetupSellerRouteError::Other(e)) => internal_error("setup_seller_info_request", e),
    }
}

/// PR-51 / session-71 — typed error from
/// [`setup_seller_info_request`]. Two arms so the route handler can
/// map `Validation` → 400 with the field-level body and `Other` →
/// 500 with the opaque internal-error body.
#[derive(Debug)]
pub enum SetupSellerRouteError {
    Validation(Vec<SellerFieldError>),
    Other(anyhow::Error),
}

/// PR-51 / session-71 — library helper that backs the
/// `POST /api/setup-seller-info` handler. Extracted as `pub` so the
/// integration test in `tests/serve_setup_seller_info_route.rs` can
/// hit it without spinning the HTTPS listener (same posture as
/// [`setup_nav_credentials_request`] per A167).
///
/// On success: writes the file and flips the boot state to Ready.
/// On validation: returns `SetupSellerRouteError::Validation` (→ 400).
/// On any other error: returns `SetupSellerRouteError::Other` (→ 500).
///
/// `path_override`: production callers (the route handler) pass
/// `None` so the helper derives `~/.aberp/<tenant>/seller.toml` from
/// HOME; the integration test passes `Some(path)` to a per-test
/// tempfile so it doesn't mutate the dev box's actual seller.toml or
/// race with cargo's parallel test runner via HOME mutation. Mirrors
/// the `get_invoice_pdf(seller_toml_override)` precedent from
/// session-58.
pub fn setup_seller_info_request(
    state: &AppState,
    inputs: &SellerInfoInputs,
    path_override: Option<&std::path::Path>,
) -> std::result::Result<(), SetupSellerRouteError> {
    let result = match path_override {
        Some(p) => setup_seller_info::setup_seller_info_to_path(p, inputs),
        None => setup_seller_info::setup_seller_info_from_inputs(state.tenant.as_str(), inputs),
    };
    match result {
        Ok(_echo) => {}
        Err(SetupSellerInfoError::Validation(fields)) => {
            return Err(SetupSellerRouteError::Validation(fields));
        }
        Err(SetupSellerInfoError::Backend(e)) => {
            return Err(SetupSellerRouteError::Other(e));
        }
    }

    // Flip to Ready. The operator_login was carried on the
    // NeedsSellerConfig variant (it was extracted at boot when NAV
    // creds loaded); pull it out so the post-transition Ready state
    // carries the same value. The Ready-already case (operator re-
    // running the wizard from a future settings screen) re-uses the
    // current operator_login.
    let mut guard = state.boot_state.write().map_err(|e| {
        SetupSellerRouteError::Other(anyhow!(
            "boot_state RwLock poisoned during seller-info setup transition: {e}"
        ))
    })?;
    let operator_login = match &*guard {
        ServeBootState::Ready { operator_login } => operator_login.clone(),
        ServeBootState::NeedsSellerConfig { operator_login } => operator_login.clone(),
        ServeBootState::NeedsSetup => {
            // Should be unreachable in practice — the route runs
            // AFTER NAV creds are present. If it fires here, that
            // means the wizard chain was driven out of order; loud-
            // fail per CLAUDE.md rule 12.
            return Err(SetupSellerRouteError::Other(anyhow!(
                "setup_seller_info_request called in NeedsSetup state — \
                 /api/setup-nav-credentials must run first"
            )));
        }
    };
    *guard = ServeBootState::Ready { operator_login };

    tracing::info!(
        tenant = %state.tenant.as_str(),
        "seller-info populated via setup route; boot state transitioned to Ready"
    );

    Ok(())
}

