pub fn delete_invoice_draft_request(
    state: &AppState,
    operator_login: &str,
    drf_id: &str,
) -> Result<invoice_draft::DeleteDraftOutcome> {
    let mut conn = Connection::open(&*state.db_path)
        .with_context(|| format!("open tenant DuckDB at {}", state.db_path.display()))?;
    invoice_draft::ensure_schema(&conn).context("ensure invoice_draft schema (defensive)")?;
    // S239 / PR-233 — defensive `ensure_schema` for the `dispatches`
    // table so the in-tx UPDATE of `spawned_invoice_id` doesn't fail
    // on a fresh tenant whose dispatch-board boot-time migration
    // hasn't been observed yet.
    aberp_dispatch::ensure_schema(&conn).context("ensure dispatch schema (defensive)")?;
    let binary_hash = state
        .binary_hash
        .wait()
        .context("binary hash unavailable")?;
    let ledger_meta = aberp_audit_ledger::LedgerMeta::new(state.tenant.clone(), binary_hash);
    let ledger_actor = Actor::from_local_cli(Ulid::new().to_string(), operator_login);
    let tx = conn
        .transaction()
        .context("begin delete_invoice_draft transaction")?;
    let outcome = invoice_draft::delete_draft_in_tx(
        &tx,
        &ledger_meta,
        ledger_actor,
        invoice_draft::DeleteDraftInputs {
            tenant: state.tenant.as_str().to_string(),
            drf_id: drf_id.to_string(),
            actor: operator_login.to_string(),
        },
    )?;
    tx.commit().context("commit delete_invoice_draft tx")?;
    if outcome.deleted {
        sync_audit_mirror_best_effort(&state.db_path, state.tenant.clone(), binary_hash);
    }
    Ok(outcome)
}

/// Best-effort audit-mirror sync after a successful write transaction.
/// Mirrors the inventory route's posture: the canonical row already
/// landed in the DB tx; a mirror failure should not poison the
/// operator's response, and the next write (or boot) will heal per
/// ADR-0030 §6's bootstrap-from-DB posture.
fn sync_audit_mirror_best_effort(
    db_path: &std::path::Path,
    tenant: aberp_audit_ledger::TenantId,
    binary_hash: aberp_audit_ledger::BinaryHash,
) {
    let mirror_path = aberp_audit_ledger::mirror_path_for(db_path);
    if let Ok(ledger) = Ledger::open(db_path, tenant, binary_hash) {
        if let Err(e) = ledger.sync_mirror(&mirror_path) {
            tracing::warn!(
                error = ?e,
                "work-order mirror sync failed; will heal on next write"
            );
        }
    }
}

// ──────────────────────────────────────────────────────────────────────
// S177 / PR-177 — AP module v1 BACKEND routes.
// ──────────────────────────────────────────────────────────────────────
//
// Six routes over the per-tenant `ap_invoice` table:
//
//   - `GET /api/incoming-invoices` — list, optional status filter +
//     pagination (`limit` + `offset`).
//   - `GET /api/incoming-invoices/:id` — detail; 404 if unknown.
//   - `POST /api/incoming-invoices/ingest` — insert a new row from
//     operator-supplied typed fields (and optional raw NAV InvoiceData
//     XML). Idempotent on `(supplier_tax_number, nav_invoice_number)`.
//   - `POST /api/incoming-invoices/:id/mark-paid` — transition to Paid.
//   - `POST /api/incoming-invoices/:id/mark-outstanding` — reset to
//     Outstanding (unwinds a prior Paid or Irrelevant mark).
//   - `POST /api/incoming-invoices/:id/mark-irrelevant` — body
//     `{ "reason": "..." }` REQUIRED.
//
// All six require_ready + bearer auth — incoming-invoice management is
// a Ready-state feature, not a first-run-setup surface.

/// Query string for `GET /api/incoming-invoices`. All fields optional;
/// `status` is closed-vocab and rejected loud if unknown
/// (the route returns 400 — silent acceptance would mask SPA bugs).
#[derive(Debug, Deserialize)]
struct ListIncomingInvoicesQuery {
    #[serde(default)]
    status: Option<String>,
    #[serde(default)]
    limit: Option<u64>,
    #[serde(default)]
    offset: Option<u64>,
}

const DEFAULT_INCOMING_LIST_LIMIT: u64 = 100;
const MAX_INCOMING_LIST_LIMIT: u64 = 500;

async fn handle_list_incoming_invoices(
    headers: HeaderMap,
    State(state): State<AppState>,
    Query(query): Query<ListIncomingInvoicesQuery>,
) -> Response {
    if let Err(resp) = require_ready(&state) {
        return resp;
    }
    if let Some(resp) = check_bearer_rejection(&headers, &state.session_token) {
        return resp;
    }
    let status_filter = match query.status.as_deref() {
        None => None,
        Some(s) => match incoming_invoices::IncomingInvoiceStatus::from_storage_str(s) {
            Ok(v) => Some(v),
            Err(e) => {
                return (
                    StatusCode::BAD_REQUEST,
                    Json(error_body(format!("invalid `status` query parameter: {e}"))),
                )
                    .into_response();
            }
        },
    };
    let limit = query
        .limit
        .unwrap_or(DEFAULT_INCOMING_LIST_LIMIT)
        .min(MAX_INCOMING_LIST_LIMIT);
    let offset = query.offset.unwrap_or(0);
    let db_path = state.db_path.clone();
    let tenant = state.tenant.clone();
    let result = tokio::task::spawn_blocking(move || {
        incoming_invoices::list_incoming(&db_path, tenant.as_str(), status_filter, limit, offset)
    })
    .await;
    match result {
        Ok(Ok(rows)) => Json(rows).into_response(),
        Ok(Err(e)) => internal_error("list_incoming_invoices", e),
        Err(join_err) => internal_error(
            "list_incoming_invoices:join",
            anyhow!("blocking task panicked: {join_err}"),
        ),
    }
}

