    /// The acknowledge route's audit half: `record_first_prod_launch_audit`
    /// MUST append exactly one `FirstProdLaunchAcknowledged` entry whose
    /// payload round-trips the timestamp + tenant. Scratch on-disk DuckDB,
    /// no `tempfile` dep, no `HOME` mutation (the touchfile half is pinned
    /// in `crate::first_launch`). The brief's POST-endpoint pin.
    #[test]
    fn record_first_prod_launch_audit_appends_one_entry() {
        let scratch = std::env::temp_dir().join(format!(
            "aberp-s166-ack-{}-{:?}",
            ulid::Ulid::new(),
            std::thread::current().id()
        ));
        std::fs::create_dir_all(&scratch).expect("create scratch dir");
        let db_path = scratch.join("test.duckdb");
        {
            let conn = Connection::open(&db_path).expect("open scratch duckdb");
            aberp_audit_ledger::ensure_schema(&conn).expect("ensure audit schema");
        }

        let tenant = TenantId::new("test").expect("tenant id");
        let bh = BinaryHash::from_bytes([0u8; 32]);
        record_first_prod_launch_audit(
            &db_path,
            tenant.clone(),
            bh,
            "operator-login",
            "2026-06-01T08:00:00Z",
        )
        .expect("record audit entry");

        let ledger = Ledger::open(&db_path, tenant, bh).expect("reopen ledger");
        let entries = ledger.entries().expect("read entries");
        let acks: Vec<_> = entries
            .iter()
            .filter(|e| e.kind == EventKind::FirstProdLaunchAcknowledged)
            .collect();
        assert_eq!(acks.len(), 1, "exactly one acknowledgement entry");
        let payload: audit_payloads::FirstProdLaunchAcknowledgedPayload =
            serde_json::from_slice(&acks[0].payload).expect("payload parses");
        assert_eq!(payload.acknowledged_at, "2026-06-01T08:00:00Z");
        assert_eq!(payload.tenant, "test");
        assert_eq!(acks[0].actor.user_id, "operator-login");

        let _ = std::fs::remove_dir_all(&scratch);
    }

    /// PR-44η / session-60 — `parse_supplier_tax_number_from_xml`
    /// MUST extract the 8-digit base supplier tax number from a
    /// NAV-emitted `<InvoiceData>` body. The load-bearing server-
    /// side derivation that lets the SPA POST submit/poll-ack
    /// without a tax-number input field per A163. A regression that
    /// silently returned an empty string (or the wrong tag's value)
    /// would surface as an `INVALID_SECURITY_USER` from NAV — a
    /// confusing failure mode CLAUDE.md rule 12 names.
    ///
    /// PR-66 / session-87 — fixtures updated to the wire-real
    /// `<common:taxpayerId>` shape (PR-50 / session-70 added the
    /// `common:` prefix to the emitter but this extractor + its
    /// fixtures missed the rename; the tests passed-but-lied per
    /// CLAUDE.md rule 9 until session 87's live error on invoice
    /// 16 surfaced the divergence).
    ///
    /// CLAUDE.md rule 9: happy path + each loud-fail arm pinned
    /// individually so a regression that collapsed validation
    /// cannot pass every assertion vacuously.
    #[test]
    fn parse_supplier_tax_number_from_xml_extracts_eight_digit_base() {
        // Happy path — well-formed body matching the wire shape
        // the PR-50 emitter writes (common: prefix on the three
        // structured children of <supplierTaxNumber>).
        let xml = b"<?xml version=\"1.0\"?>\
            <InvoiceData>\
            <invoiceNumber>INV-default/00013</invoiceNumber>\
            <invoiceMain><invoice><invoiceHead>\
            <supplierInfo>\
            <supplierTaxNumber><common:taxpayerId>12345678</common:taxpayerId><common:vatCode>1</common:vatCode><common:countyCode>42</common:countyCode></supplierTaxNumber>\
            <supplierName>Test Kft.</supplierName>\
            </supplierInfo>\
            </invoiceHead></invoice></invoiceMain></InvoiceData>";
        assert_eq!(parse_supplier_tax_number_from_xml(xml).unwrap(), "12345678");
    }

    #[test]
    fn parse_supplier_tax_number_from_xml_rejects_missing_tag() {
        let xml = b"<?xml version=\"1.0\"?>\
            <InvoiceData><invoiceNumber>X</invoiceNumber></InvoiceData>";
        let err = parse_supplier_tax_number_from_xml(xml).unwrap_err();
        let msg = format!("{err:#}");
        assert!(
            msg.contains("supplierTaxNumber"),
            "missing-tag error must name the element: {msg}"
        );
    }

    /// PR-66 / session-87 — the exact regression class that bit
